// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
// CONTADOR DE VISITAS Y ESTADÃSTICAS DE USO â€” localStorage
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
(function() {
  const STATS_KEY = 'manga_stats_v4';

  function getStats() {
    return SafeStorage.getJSON(STATS_KEY, {});
  }
  function saveStats(s) {
    SafeStorage.setJSON(STATS_KEY, s);
  }

  // â”€â”€ API pÃºblica para trackear eventos â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  window._trackStat = function(key) {
    const s = getStats();
    s[key] = (s[key] || 0) + 1;
    saveStats(s);
  };

  // â”€â”€ Contar visita al cargar â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  document.addEventListener('DOMContentLoaded', function() {
    window._trackStat('visitas');
    const s = getStats();

    // Mostrar visitas en el header â€” solo cuando el dato existe (M-03).
    const el = document.getElementById('visitCountGlobal');
    const wrap = document.querySelector('.visit-counter-portada');
    const v = s.visitas;
    if (el && typeof v === 'number' && v > 0) {
      el.textContent = v.toLocaleString('es-ES');
      if (wrap) wrap.removeAttribute('hidden');
    } else if (wrap) {
      wrap.setAttribute('hidden', '');
    }

    // Parchear funciones principales para registrar uso
    setTimeout(() => {
      [
        ['openFicha',        'fichas_abiertas'],
        ['openRubrica',      'rubricas_abiertas'],
        ['openLectura',      'lecturas_abiertas'],
        ['openExpres',       'expres_abiertas'],
        ['generarSecuencia', 'secuencias_generadas'],
        ['generarRubrica',   'rubricas_generadas'],
      ].forEach(([fn, stat]) => {
        const orig = window[fn];
        if (typeof orig === 'function' && !orig._tracked) {
          window[fn] = function(...args) {
            window._trackStat(stat);
            return orig.apply(this, args);
          };
          window[fn]._tracked = true;
        }
      });
    }, 600);
  });

  // â”€â”€ Panel de estadÃ­sticas â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  window.showStats = function() { openPanelDocente('stats'); };
})();

/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   Panel docente unificado â€” openPanelDocente()
   v1.0 Â· El manga como recurso didÃ¡ctico Â· ULPGC

   ReÃºne en un Ãºnico modal con cuatro pestaÃ±as los datos del docente
   que anteriormente vivÃ­an en cuatro paneles separados:
     Â· EstadÃ­sticas de uso (contadores acumulados)
     Â· Notas de ficha (observaciones, valoraciones por tÃ­tulo)
     Â· Historial (sesiÃ³n actual + visitas anteriores)
     Â· Exportar (JSON + CSV)

   Acceso: FAB â†’ icono docente, o llamada directa desde showStats().
   Compatible con FocusTrap y dark mode.
â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */

/**
 * Abre el panel docente unificado en la pestaÃ±a indicada.
 * @param {'stats'|'notas'|'historial'|'exportar'} [tab='stats']
 */
function openPanelDocente(tab = 'stats') {
  const _opener = document.activeElement;

  let overlay = document.getElementById('panelDocenteOverlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'panelDocenteOverlay';
    overlay.setAttribute('role', 'dialog');
    overlay.setAttribute('aria-modal', 'true');
    overlay.setAttribute('aria-labelledby', 'panelDocenteTitle');
    overlay.className = 'panel-docente-overlay';
    document.body.appendChild(overlay);
    overlay.addEventListener('click', e => {
      if (e.target === overlay) closePanelDocente();
    });
  }

  overlay.innerHTML = `
    <div class="panel-docente-modal" id="panelDocenteModal">
      <div class="panel-docente-header">
        <span id="panelDocenteTitle" class="panel-docente-title">Panel docente</span>
        <button type="button" class="panel-docente-close" data-action="closePanelDocente"
                aria-label="Cerrar panel">âœ•</button>
      </div>

      <nav class="panel-docente-tabs" role="tablist" aria-label="Secciones del panel docente">
        ${[
          { id:'stats',    icon:'ðŸ“Š', label:'EstadÃ­sticas' },
          { id:'notas',    icon:'âœŽ',  label:'Notas'        },
          { id:'historial',icon:'â§–',  label:'Historial'    },
          { id:'exportar', icon:'â¬‡',  label:'Exportar'     },
          { id:'catalogo', icon:'âœš',  label:'CatÃ¡logo'     },
        ].map(t => `
          <button type="button"
                  role="tab"
                  id="pd-tab-${t.id}"
                  aria-controls="pd-panel-${t.id}"
                  aria-selected="${t.id === tab ? 'true' : 'false'}"
                  class="pd-tab${t.id === tab ? ' active' : ''}"
                  data-action="switchPanelDocenteTab" data-arg="${t.id}">
            <span aria-hidden="true">${t.icon}</span> ${t.label}
          </button>`).join('')}
      </nav>

      <div class="panel-docente-body" id="panelDocenteBody"
           role="tabpanel" aria-labelledby="pd-tab-${tab}">
        <!-- Contenido inyectado por _renderPdTab() -->
      </div>
    </div>`;

  overlay.style.display = 'flex';
  document.body.style.overflow = 'hidden';
  FocusTrap.activate(document.getElementById('panelDocenteModal'), _opener);
  _renderPdTab(tab);
}

function closePanelDocente() {
  const overlay = document.getElementById('panelDocenteOverlay');
  if (overlay) overlay.style.display = 'none';
  document.body.style.overflow = '';
  FocusTrap.deactivate();
}

/**
 * Cambia la pestaÃ±a activa del panel docente.
 * @param {string} tab
 */
function switchPanelDocenteTab(tab) {
  document.querySelectorAll('.pd-tab').forEach(btn => {
    const isActive = btn.dataset.arg === tab;
    btn.classList.toggle('active', isActive);
    btn.setAttribute('aria-selected', isActive ? 'true' : 'false');
  });
  const body = document.getElementById('panelDocenteBody');
  if (body) body.setAttribute('aria-labelledby', `pd-tab-${tab}`);
  _renderPdTab(tab);
}

/**
 * Renderiza el contenido de la pestaÃ±a activa.
 * @param {string} tab
 */
function _renderPdTab(tab) {
  const body = document.getElementById('panelDocenteBody');
  if (!body) return;

  switch (tab) {
    case 'stats':    _pdStats(body);    break;
    case 'notas':    _pdNotas(body);    break;
    case 'historial':_pdHistorial(body);break;
    case 'exportar': _pdExportar(body); break;
    case 'catalogo': _pdCatalogo(body); break;
  }
}

