/**
 * Inicializa los handlers de arrastre y selecciÃ³n de archivo en la zona de importaciÃ³n.
 * Se llama desde _pdCatalogo() tras renderizar el HTML.
 */
function _initPdCatImport() {
  const drop  = document.getElementById('pdCatDrop');
  const input = document.getElementById('pdCatFileInput');
  if (!drop || !input) return;

  // Teclado: Enter/Space activa el input de archivo
  drop.addEventListener('keydown', e => {
    if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); input.click(); }
  });

  // Drag & drop
  ['dragenter','dragover'].forEach(ev => drop.addEventListener(ev, e => {
    e.preventDefault(); drop.classList.add('pd-import-drop--active');
  }));
  ['dragleave','dragend'].forEach(ev => drop.addEventListener(ev, () => {
    drop.classList.remove('pd-import-drop--active');
  }));
  drop.addEventListener('drop', e => {
    e.preventDefault();
    drop.classList.remove('pd-import-drop--active');
    const file = e.dataTransfer?.files?.[0];
    if (file) _processPdCatFile(file);
  });

  // File input
  input.addEventListener('change', () => {
    const file = input.files?.[0];
    if (file) _processPdCatFile(file);
    input.value = ''; // permitir reimportar el mismo archivo
  });
}

/**
 * Lee un archivo y lo pasa al importador adecuado segÃºn extensiÃ³n.
 * @param {File} file
 */
function _processPdCatFile(file) {
  const result = document.getElementById('pdCatImportResult');
  if (!result) return;

  const mode = document.querySelector('[name="pdCatMode"]:checked')?.value || 'merge';
  const ext  = file.name.split('.').pop().toLowerCase();

  if (!['csv','json'].includes(ext)) {
    _showImportResult(result, { ok:0, skipped:0, errors:[`Formato no soportado: .${ext}. Solo se aceptan .csv y .json.`] });
    return;
  }

  result.style.display = 'block';
  result.className = 'pd-import-result pd-import-result--loading';
  result.textContent = `Procesando ${file.name}â€¦`;

  const reader = new FileReader();
  reader.onload = e => {
    const text   = e.target.result;
    const report = ext === 'json'
      ? CatalogoLocal.importJSON(text, mode)
      : CatalogoLocal.importCSV(text, mode);

    _showImportResult(result, report, file.name);

    if (report.ok > 0) {
      _refreshCatalogoEfectivo();
      ValidadorEsquema.validateAndReport(CATALOGO_EFECTIVO);
      renderCatalog();
      Logger.debug('CatalogoLocal', `Importados ${report.ok} tÃ­tulos desde ${file.name}`);
    }
  };
  reader.onerror = () => {
    _showImportResult(result, { ok:0, skipped:0, errors:['Error al leer el archivo.'] }, file.name);
  };
  reader.readAsText(file, 'UTF-8');
}

/**
 * Muestra el resultado de la importaciÃ³n en el Ã¡rea de resultado.
 * @param {HTMLElement} el
 * @param {{ ok: number, skipped: number, errors: string[] }} report
 * @param {string} [filename]
 */
function _showImportResult(el, report, filename = '') {
  const hasErrors = report.errors?.length > 0;
  const isSuccess = report.ok > 0 && !hasErrors;

  el.className = `pd-import-result pd-import-result--${isSuccess ? 'ok' : hasErrors ? 'error' : 'warn'}`;
  el.style.display = 'block';

  let html = filename ? `<strong>${escapeHtml(filename)}</strong><br>` : '';
  if (report.ok)      html += `âœ“ ${report.ok} tÃ­tulo${report.ok !== 1 ? 's' : ''} importado${report.ok !== 1 ? 's' : ''}. `;
  if (report.skipped) html += `âŠ˜ ${report.skipped} omitido${report.skipped !== 1 ? 's' : ''}. `;
  if (hasErrors)      html += `<br><span class="pd-import-errors">${report.errors.map(e => `âš  ${escapeHtml(e)}`).join('<br>')}</span>`;
  if (isSuccess)      html += `<br><small>El catÃ¡logo se ha actualizado. Los cambios son visibles en el grid de tÃ­tulos.</small>`;

  el.innerHTML = html;
}

