function _pdCatalogoEliminar(titulo) {
  if (!confirm(`Â¿Eliminar Â«${titulo}Â» del catÃ¡logo activo? La entrada base de datos.js no se modifica.`)) return;
  CatalogoLocal.deleteEntry(titulo);
  _refreshCatalogoEfectivo();
  renderCatalog();
  const body = document.getElementById('panelDocenteBody');
  if (body) _pdCatalogo(body);
}

function _pdCatalogoExportJSON() { CatalogoLocal.exportJSON(); }
