/**
 * Valida el catÃ¡logo efectivo y muestra el resultado en el panel docente.
 */
function _pdCatalogoValidar() {
  const result  = ValidadorEsquema.validate(CATALOGO_EFECTIVO);
  const total   = CATALOGO_EFECTIVO.length;
  const totalProblemas = result.errors.length + result.warnings.length;

  if (!totalProblemas) {
    alert(`âœ“ CatÃ¡logo vÃ¡lido\n${total} tÃ­tulos sin errores ni advertencias.`);
    return;
  }

  const lines = [
    `CatÃ¡logo: ${total} tÃ­tulos`,
    result.errors.length   ? `ðŸš¨ ${result.errors.length} error${result.errors.length > 1 ? 'es' : ''}:`   : '',
    ...result.errors.slice(0, 10).map(e => `  Â· ${e}`),
    result.errors.length > 10 ? `  â€¦ y ${result.errors.length - 10} mÃ¡s (ver consola F12)` : '',
    result.warnings.length ? `âš  ${result.warnings.length} aviso${result.warnings.length > 1 ? 's' : ''}:` : '',
    ...result.warnings.slice(0, 5).map(w => `  Â· ${w}`),
  ].filter(Boolean).join('\n');

  alert(lines);
  Logger.error('Esquema', `ValidaciÃ³n manual: ${result.errors.length} errores, ${result.warnings.length} avisos`);
}

function _pdCatalogoReset() {
  if (!confirm('Â¿Descartar todas las modificaciones locales y volver al catÃ¡logo base de datos.js?')) return;
  CatalogoLocal.resetLocal();
  _refreshCatalogoEfectivo();
  renderCatalog();
  const body = document.getElementById('panelDocenteBody');
  if (body) _pdCatalogo(body);
}

