// â”€â”€ VersiÃ³n imprimible â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€


// â”€â”€ Keyboard navigation for all tab systems â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function initTabKeyboard(tabListSelector) {
  document.querySelectorAll(tabListSelector).forEach(tablist => {
    const tabs = Array.from(tablist.querySelectorAll('[role="tab"]'));
    tabs.forEach((tab, i) => {
      tab.addEventListener('keydown', e => {
        let idx = i;
        if (e.key === 'ArrowRight' || e.key === 'ArrowDown') {
          idx = (i + 1) % tabs.length;
        } else if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') {
          idx = (i - 1 + tabs.length) % tabs.length;
        } else if (e.key === 'Home') {
          idx = 0;
        } else if (e.key === 'End') {
          idx = tabs.length - 1;
        } else { return; }
        e.preventDefault();
        // Synthesise a minimal event object so show* functions receive the target
        tabs[idx].dispatchEvent(new MouseEvent('click', { bubbles: true }));
        tabs[idx].focus();
      });
    });
  });
}

// â”€â”€ Init keyboard nav â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
document.addEventListener('DOMContentLoaded', () => {
  initTabKeyboard('[role="tablist"]');
});

// â”€â”€ Copiar cita APA â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function copyCitation() {
  const text = `Biblioteca del Campus del Obelisco Â· Aula de CÃ³mic, Facultad de Ciencias de la EducaciÃ³n, Universidad de Las Palmas de Gran Canaria. (2026). El manga como recurso didÃ¡ctico: lÃ­nea del tiempo interactiva y catÃ¡logo pedagÃ³gico.`;
  navigator.clipboard.writeText(text).then(() => {
    const btn = document.querySelector('.citation-copy');
    btn.textContent = 'âœ“ Copiado';
    btn.classList.add('citation-copied');
    setTimeout(() => {
      btn.textContent = 'Copiar';
      btn.classList.remove('citation-copied');
    }, 2500);
  }).catch(() => {
    // Fallback for older browsers
    const ta = document.createElement('textarea');
    ta.value = text; document.body.appendChild(ta);
    ta.select(); document.execCommand('copy');
    document.body.removeChild(ta);
  });
}

// â”€â”€ Modo aula â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let modoAulaActive = false;

function toggleModoAula() {
  modoAulaActive = !modoAulaActive;
  document.body.classList.toggle('modo-aula', modoAulaActive);

  // Count sensitive cards
  const sensitiveCount = document.querySelectorAll('.cat-card[data-sensitive]').length;

  const btn = document.querySelector('.modo-aula-btn');
  if (btn) {
    btn.textContent = modoAulaActive
      ? `âœ“ Modo aula (${sensitiveCount} tÃ­tulos ocultos)`
      : 'ðŸ« Modo aula';
    btn.setAttribute('aria-pressed', modoAulaActive ? 'true' : 'false');
  }
  // Update catalog count
  searchCatalog(document.getElementById('catalogSearch')?.value || '');
  // Announce to screen readers
  const notice = document.querySelector('.modo-aula-notice');
  if (notice) notice.textContent = modoAulaActive
    ? `Modo aula activo: ${sensitiveCount} tÃ­tulos con contenido adulto o sensible han sido ocultados del catÃ¡logo.`
    : '';

  // Scroll to catalog section so user sees the effect
  if (modoAulaActive) {
    const cat = document.getElementById('catalogo');
    if (cat) cat.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}


