// â”€â”€ Tarjeta virtual para lÃ­nea del tiempo â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Crea un elemento DOM mÃ­nimo compatible con openFicha/openLectura/
// openExpres/openRubrica a partir de los datos de una tarjeta .card
function _makeVirtualCard(title, author, tip, uso, nivel) {
  const div = document.createElement('div');
  div.setAttribute('data-uso',   uso   || 'visual');
  div.setAttribute('data-nivel', nivel || 'secundaria bachillerato');
  div.setAttribute('data-tip',   tip   || '');

  const titleSpan = document.createElement('span');
  titleSpan.className = 'cat-title';
  titleSpan.textContent = title;

  const authorSpan = document.createElement('span');
  authorSpan.className = 'cat-author';
  authorSpan.textContent = author;

  div.appendChild(titleSpan);
  div.appendChild(authorSpan);
  return div;
}

function openVitrina(card) {
  ensureVitrinaUI();
  const vitrineId = card.getAttribute('data-vitrina');
  if (!vitrineId) return;
  const title  = card.querySelector('.ct')?.textContent || '';
  const author = card.querySelector('.ca')?.textContent || '';
  const tip    = card.getAttribute('data-tip') || '';
  const uso    = card.getAttribute('data-uso')   || '';
  const nivel  = card.getAttribute('data-nivel') || '';
  let eraName = '', eraColor = 'B8860B';
  const col = card.closest('.col');
  if (col) {
    const eraN = col.querySelector('.era-name');
    if (eraN) eraName = eraN.textContent;
    const bar = col.querySelector('.bar');
    if (bar) {
      const bg = bar.style.background || '';
      const hex = bg.match(/#([0-9a-fA-F]{6})/);
      if (hex) eraColor = hex[1];
    }
  }
  document.getElementById('vitrineStripe').style.background = '#' + eraColor;
  document.getElementById('vitrineEraTag').textContent  = eraName || 'LÃ­nea del tiempo';
  document.getElementById('vitrineTitle').textContent   = title;
  // Western period in vitrina
  const periodoEl = document.getElementById('vitrinePeriodo');
  if (periodoEl) {
    const periodo = card.getAttribute('data-periodo') || '';
    periodoEl.textContent = periodo ? 'ðŸŒ ' + periodo : '';
    periodoEl.style.display = periodo ? 'block' : 'none';
  }
  // OPAC search link
  const opacEl = document.getElementById('vitrineOpacLink');
  if (opacEl) {
    const slug = encodeURIComponent(title.trim()).replace(/%20/g, '+');
    opacEl.href = 'https://opac.ulpgc.es/cgi-bin/abnetopac?ACCION=SREQ&q=TI%3D' + slug;
    opacEl.style.display = 'block';
  }
  document.getElementById('vitrineAuthor').textContent  = author;
  const tempDiv = document.createElement('div');
  tempDiv.innerHTML = sanitizeHtml(tip);
  document.getElementById('vitrineDesc').textContent = tempDiv.textContent || tip;
  const metaEl = document.getElementById('vitrineMeta');
  metaEl.innerHTML = '';
  uso.split(' ').forEach(u => {
    if (!u) return;
    const b = document.createElement('span');
    b.className = 'vitrina-badge';
    b.style.background = '#' + (USO_COLORS_V[u] || '888888');
    b.textContent = USO_LABELS_V[u] || u;
    metaEl.appendChild(b);
  });
  nivel.split(' ').forEach(n => {
    if (!n) return;
    const b = document.createElement('span');
    b.className = 'vitrina-nivel-tag';
    b.textContent = NIVEL_LABELS_V[n] || n;
    metaEl.appendChild(b);
  });
  // Build classroom activity ficha
  buildFicha(uso, nivel);

  // â”€â”€ Botones de acciÃ³n pedagÃ³gica â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  // Construir tarjeta virtual compatible con openFicha/openLectura/openExpres/openRubrica
  const vCard = _makeVirtualCard(title, author, tip, uso, nivel);
  const fichaBtn   = document.getElementById('vitrineFichaBtn');
  const rubricaBtn = document.getElementById('vitrineRubricaBtn');
  const lecturaBtn = document.getElementById('vitrineLecturaBtn');
  const expresBtn  = document.getElementById('vitrineExpresBtn');

  if (fichaBtn)   fichaBtn.onclick   = () => { closeVitrina(); openFicha(vCard); };
  if (rubricaBtn) rubricaBtn.onclick = () => { closeVitrina(); openRubrica(vCard); };
  if (lecturaBtn) lecturaBtn.onclick = () => { closeVitrina(); openLectura(vCard); };
  if (expresBtn)  expresBtn.onclick  = () => { closeVitrina(); window.openExpres(vCard); };

  const related = Array.from(document.querySelectorAll('.card[data-vitrina="' + vitrineId + '"]'))
    .filter(c => c !== card);
  const relSec  = document.getElementById('vitrineRelated');
  const relList = document.getElementById('vitrineRelatedList');
  relList.innerHTML = '';
  if (related.length > 0) {
    relSec.style.display = 'block';
    related.forEach(rc => {
      const rt = rc.querySelector('.ct')?.textContent || '';
      const ra = rc.querySelector('.ca')?.textContent || '';
      let reraName = '';
      const rcol = rc.closest('.col');
      if (rcol) { const ren = rcol.querySelector('.era-name'); if(ren) reraName = ren.textContent; }
      const item = document.createElement('div');
      item.className = 'vitrina-related-item';
      item.setAttribute('role', 'button');
      item.setAttribute('tabindex', '0');
      item.innerHTML = '<span class="vitrina-related-era">' + reraName + '</span>' +
        '<span class="vitrina-related-title">' + rt + '</span>' +
        '<span class="vitrina-related-author">' + ra + '</span>';
      item.addEventListener('click', () => openVitrina(rc));
      item.addEventListener('keydown', e => { if(e.key==='Enter'||e.key===' '){e.preventDefault();openVitrina(rc);}});
      relList.appendChild(item);
    });
  } else { relSec.style.display = 'none'; }
  const overlay = document.getElementById('vitrineOverlay');
  const drawer  = document.getElementById('vitrineDrawer');
  overlay.classList.add('open');
  drawer.classList.add('open');
  drawer.setAttribute('aria-hidden', 'false');
  // Track which card opened the drawer so focus returns on close
  drawer._triggerCard = card;
  drawer.querySelector('.vitrina-close').focus();
  drawer._escH = e => { if(e.key==='Escape') closeVitrina(); };
  document.addEventListener('keydown', drawer._escH);
}

// â”€â”€ Itinerarios universitarios tabs â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function showUniv(id, ev) {
  const btn = ev && ev.target ? ev.target : document.querySelector(`[aria-controls="univ-${id}"]`);
  _activateTab('univ', 'univ-tab', id, btn);
}

function closeVitrina() {
  const overlay = document.getElementById('vitrineOverlay');
  const drawer  = document.getElementById('vitrineDrawer');
  overlay.classList.remove('open');
  drawer.classList.remove('open');
  drawer.setAttribute('aria-hidden', 'true');
  if (drawer._escH) { document.removeEventListener('keydown', drawer._escH); drawer._escH = null; }
  // Return focus to the card that opened the drawer
  if (drawer._triggerCard) {
    drawer._triggerCard.focus();
    drawer._triggerCard = null;
  }
}


