function openFicha(card) {
  if (!card) return;
  if (typeof card.querySelector !== 'function') return;
  const _opener = document.activeElement;
  const title  = card.querySelector('.cat-title')?.textContent?.trim() || '';
  const author = card.querySelector('.cat-author')?.textContent?.trim() || '';
  const tip    = card.getAttribute('data-tip') || 'Sin descripciÃ³n disponible.';
  const usos   = (card.getAttribute('data-uso') || '').split(/\s+/).filter(Boolean);
  const uso1   = usos[0] || 'visual';
  const niveles = (card.getAttribute('data-nivel') || '').split(/\s+/).filter(Boolean);

  document.getElementById('fichaTitleEl').textContent = title;
  document.getElementById('fichaAuthor').textContent  = author;
  document.getElementById('fichaDesc').textContent    = tip;
  document.getElementById('fichaBadges').innerHTML = usos.map(u =>
    `<span class="ficha-badge" style="background:${USO_COLORS_F[u] || '#5a3a1a'}">${USO_LABELS_F[u] || u}</span>`
  ).join('');
  document.getElementById('fichaNiv').textContent = niveles.map(n => NIV_LABELS_F[n] || n).join(' Â· ');
  document.getElementById('fichaQuestions').innerHTML = generateQuestions(tip, uso1, title);
  document.getElementById('fichaLomloe').textContent = lomloeConnection(uso1);

  // â”€â”€ Cargar notas docentes â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  loadFichaNotas(title);

  document.getElementById('fichaOverlay')?.classList.add('open');
  document.body.style.overflow = 'hidden';
  FocusTrap.activate(document.getElementById('fichaModal'), _opener);
  if (typeof logActivity === 'function') logActivity('viewed', { title, section: 'Ficha de aula' });
}

// â”€â”€ Clave de almacenamiento por tÃ­tulo â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function fichaNotasKey(title) {
  return 'manga_notas__' + title.slice(0, 80).replace(/\s+/g, '_');
}

// â”€â”€ Hints para la escala de estrellas â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const STAR_HINTS = ['','Muy baja','Baja','Media','Alta','Muy alta'];

// â”€â”€ Cargar notas en los campos â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function loadFichaNotas(title) {
  const key  = fichaNotasKey(title);
  const data = SafeStorage.getJSON(key, {});

  document.getElementById('fichaNotaObs').value   = data.obs   || '';
  document.getElementById('fichaNotaAdapt').value = data.adapt || '';
  document.getElementById('fichaNotaSeg').value   = data.seg   || '';

  // Estrellas
  const stars = document.querySelectorAll('.ficha-star');
  const val   = parseInt(data.stars || '0', 10);
  stars.forEach(s => s.classList.toggle('on', parseInt(s.dataset.val) <= val));
  document.getElementById('fichaStarHint').textContent = val ? STAR_HINTS[val] : '';

  // Guardar tÃ­tulo activo en el modal para el autosave
  document.getElementById('fichaModal').dataset.activeTitle = title;
  document.getElementById('fichaNotasSaved').classList.remove('show');
}

// â”€â”€ Autoguardado â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let _fichaNotasTimer = null;
function saveFichaNotas() {
  const title = document.getElementById('fichaModal')?.dataset.activeTitle || '';
  if (!title) return;
  const key = fichaNotasKey(title);
  const val = parseInt(document.querySelector('.ficha-star.on:last-of-type')?.dataset.val || '0');
  // Count filled-on stars properly
  let starVal = 0;
  document.querySelectorAll('.ficha-star').forEach(s => { if (s.classList.contains('on')) starVal = parseInt(s.dataset.val); });
  const data = {
    obs:   document.getElementById('fichaNotaObs')?.value   || '',
    adapt: document.getElementById('fichaNotaAdapt')?.value || '',
    seg:   document.getElementById('fichaNotaSeg')?.value   || '',
    stars: starVal,
    ts:    new Date().toISOString()
  };
  const hasContent = data.obs || data.adapt || data.seg || data.stars;
  if (hasContent) {
    SafeStorage.setJSON(key, data);
  } else {
    SafeStorage.removeItem(key);
  }
  // Flash "Guardado"
  const saved = document.getElementById('fichaNotasSaved');
  if (saved) { saved.classList.add('show'); clearTimeout(_fichaNotasTimer); _fichaNotasTimer = setTimeout(() => saved.classList.remove('show'), 1800); }
  // Update card indicator
  updateNotasIndicator(title, !!hasContent);
}

function updateNotasIndicator(title, hasNotes) {
  document.querySelectorAll('.cat-card').forEach(card => {
    const t = card.querySelector('.cat-title')?.textContent?.trim();
    if (t === title) card.classList.toggle('has-notas', hasNotes);
  });
}

// â”€â”€ Init: wire up autosave y estrellas â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
document.addEventListener('DOMContentLoaded', function() {
  // Textareas â†’ autosave debounced
  ['fichaNotaObs','fichaNotaAdapt','fichaNotaSeg'].forEach(id => {
    document.getElementById(id)?.addEventListener('input', () => {
      clearTimeout(_fichaNotasTimer);
      _fichaNotasTimer = setTimeout(saveFichaNotas, 600);
    });
  });

  // Estrellas
  document.querySelectorAll('.ficha-star').forEach(star => {
    star.addEventListener('click', function() {
      const val = parseInt(this.dataset.val);
      const stars = document.querySelectorAll('.ficha-star');
      let newVal = val;
      // Click on already-active last star â†’ deselect
      const currentVal = parseInt(document.querySelector('.ficha-star.on:last-of-type')?.dataset.val || '0');
      if (currentVal === val) newVal = 0;
      stars.forEach(s => s.classList.toggle('on', parseInt(s.dataset.val) <= newVal));
      document.getElementById('fichaStarHint').textContent = newVal ? STAR_HINTS[newVal] : '';
      saveFichaNotas();
    });
    star.addEventListener('mouseenter', function() {
      const v = parseInt(this.dataset.val);
      document.getElementById('fichaStarHint').textContent = STAR_HINTS[v] || '';
    });
    star.addEventListener('mouseleave', function() {
      const currentVal = parseInt(document.querySelector('.ficha-star.on:last-of-type')?.dataset.val || '0');
      document.getElementById('fichaStarHint').textContent = currentVal ? STAR_HINTS[currentVal] : '';
    });
  });

  // Marcar tarjetas que ya tienen notas guardadas
  document.querySelectorAll('.cat-card').forEach(card => {
    const title = card.querySelector('.cat-title')?.textContent?.trim() || '';
    if (!title) return;
    try {
      const stored = SafeStorage.getItem(fichaNotasKey(title));
      if (stored) card.classList.add('has-notas');
    } catch(e) {}
  });
});

function closeFicha() {
  document.getElementById('fichaOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
  FocusTrap.deactivate();
}

const compSelection = new Map();

function toggleComp(btn) {
  const card = btn?.closest('.cat-card');
  if (!card) return;
  const title = card.querySelector('.cat-title')?.textContent?.trim() || '';
  const key = title.slice(0, 40);

  if (compSelection.has(key)) {
    compSelection.delete(key);
    btn.classList.remove('selected');
    btn.textContent = 'âŠ• Comparar';
  } else {
    if (compSelection.size >= 3) return;
    compSelection.set(key, {
      title,
      author: card.querySelector('.cat-author')?.textContent?.trim() || '',
      uso: (card.getAttribute('data-uso') || '').split(/\s+/)[0] || 'visual',
      nivel: card.getAttribute('data-nivel') || '',
      tip: card.getAttribute('data-tip') || '',
      periodo: card.querySelector('.periodo-badge')?.textContent?.trim() || 'â€”',
      opacUrl: card.querySelector('.cat-opac-link')?.href || ''
    });
    btn.classList.add('selected');
    btn.textContent = 'âœ“ AÃ±adido';
  }
  updateCompDrawer();
}

function updateCompDrawer() {
  const drawer = document.getElementById('compDrawer');
  const goBtn = document.getElementById('compGoBtn');
  const slots = ['compSlot0','compSlot1','compSlot2'].map(id => document.getElementById(id));
  const items = [...compSelection.values()];

  slots.forEach((slot, i) => {
    if (!slot) return;
    if (items[i]) {
      slot.textContent = items[i].title;
      slot.classList.add('filled');
      slot.onclick = () => removeFromComp(items[i].title);
      slot.title = 'Clic para quitar';
    } else {
      slot.textContent = i === 0 ? '+ AÃ±ade un tÃ­tulo' : `TÃ­tulo ${i + 1}`;
      slot.classList.remove('filled');
      slot.onclick = null;
      slot.title = '';
    }
  });

  if (drawer) drawer.classList.toggle('visible', items.length > 0);
  if (goBtn) goBtn.disabled = items.length < 2;
}

function removeFromComp(title) {
  const key = title.slice(0, 40);
  compSelection.delete(key);
  document.querySelectorAll('.cat-comp-btn').forEach(btn => {
    const t = btn.closest('.cat-card')?.querySelector('.cat-title')?.textContent?.trim() || '';
    if (t.slice(0, 40) === key) {
      btn.classList.remove('selected');
      btn.textContent = 'âŠ• Comparar';
    }
  });
  updateCompDrawer();
}

function clearComp() {
  compSelection.clear();
  document.querySelectorAll('.cat-comp-btn').forEach(btn => {
    btn.classList.remove('selected');
    btn.textContent = 'âŠ• Comparar';
  });
  updateCompDrawer();
}

