// PREGUNTAS DETONADORAS POR ERA HISTÃ“RICA
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
(function() {

  // â”€â”€ Preguntas por era â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const ERA_QUESTIONS = {
    'Heian': {
      nivel: 'Secundaria Â· Bachillerato Â· Universidad',
      preguntas: [
        'Â¿Por quÃ© el arte japonÃ©s mÃ¡s refinado naciÃ³ en un perÃ­odo de paz aristocrÃ¡tica? Â¿QuÃ© condiciones sociales permiten que florezca la cultura?',
        'Las ChÅjÅ«-giga muestran animales que se comportan como humanos criticando a la nobleza. Â¿QuÃ© tradiciÃ³n artÃ­stica occidental conoces que use el mismo recurso?'
      ]
    },
    'Kamakura Â· Muromachi': {
      nivel: 'Secundaria Â· Bachillerato',
      preguntas: [
        'JapÃ³n pasÃ³ de una nobleza cortesana a una clase guerrera (samurÃ¡i) en el poder. Â¿Conoces en la historia occidental algÃºn cambio de Ã©lite similar?',
        'El bushido establece un cÃ³digo de honor estricto. Â¿En quÃ© se parece y en quÃ© se diferencia del cÃ³digo caballeresco europeo medieval?'
      ]
    },
    'Sengoku Â· Momoyama': {
      nivel: 'Secundaria Â· Bachillerato',
      preguntas: [
        'El Sengoku es un siglo de guerra civil continua. Â¿QuÃ© condiciones polÃ­ticas explican que un paÃ­s fragmentado en seÃ±orÃ­os rivales acabe unificÃ¡ndose?',
        'Â¿Por quÃ© crees que la cultura japonesa (teatro NÅ, ceremonia del tÃ©, jardines zen) alcanzÃ³ una refinaciÃ³n extrema justo en un perÃ­odo de violencia mÃ¡xima?'
      ]
    },
    'Edo': {
      nivel: 'Secundaria Â· Bachillerato Â· Universidad',
      preguntas: [
        'JapÃ³n cerrÃ³ sus fronteras al mundo exterior durante mÃ¡s de 200 aÃ±os (sakoku). Â¿QuÃ© consecuencias tuvo ese aislamiento en su desarrollo cultural, tecnolÃ³gico y econÃ³mico?',
        'Hokusai publica en 1814 los cuadernos que darÃ¡n nombre al manga. Â¿Por quÃ© una cultura con siglos de arte visual secuencial tarda tanto en crear un tÃ©rmino propio para nombrarlo?'
      ]
    },
    'Meiji': {
      nivel: 'Secundaria Â· Bachillerato',
      preguntas: [
        'JapÃ³n pasÃ³ en pocas dÃ©cadas de feudalismo a potencia industrial moderna. Â¿QuÃ© pierde y quÃ© gana una sociedad cuando moderniza a marcha forzada?',
        'Los primeros manga de la era Meiji copiaron tÃ©cnicas de la caricatura occidental. Â¿Es copiar una forma de resistencia cultural o de colonizaciÃ³n cultural? Â¿Puede ser las dos cosas?'
      ]
    },
    'TaishÅ': {
      nivel: 'Secundaria Â· Bachillerato',
      preguntas: [
        'La era TaishÅ fue la mÃ¡s democrÃ¡tica y cosmopolita del JapÃ³n premoderno. Â¿Por quÃ© durÃ³ tan poco? Â¿QuÃ© factores histÃ³ricos pueden truncar un perÃ­odo liberal?',
        'El manga cÃ³mico de esta Ã©poca mezcla humor absurdo con crÃ­tica social. Â¿QuÃ© otras formas artÃ­sticas conoces que usen el humor para decir verdades incÃ³modas?'
      ]
    },
    'ShÅwa': {
      nivel: 'Secundaria Â· Bachillerato Â· Universidad',
      preguntas: [
        'Tezuka sobreviviÃ³ los bombardeos de Osaka y en 1952 crea a Astroboy, un niÃ±o-robot sÃ­mbolo de esperanza. Â¿CÃ³mo puede el trauma colectivo transformarse en arte que mira al futuro?',
        'El manga de posguerra naciÃ³ en revistas de alquiler para niÃ±os pobres que no podÃ­an comprarlas. Â¿QuÃ© relaciÃ³n existe entre la precariedad econÃ³mica y la explosiÃ³n de una forma artÃ­stica popular?'
      ]
    },
    'Heisei': {
      nivel: 'ESO Â· Bachillerato Â· Universidad',
      preguntas: [
        'El manga Heisei tematiza el miedo a la tecnologÃ­a, la identidad lÃ­quida y el fin del mundo. Â¿En quÃ© medida esos miedos de los aÃ±os 90 japoneses siguen siendo los nuestros hoy?',
        'JapÃ³n exportÃ³ su cultura pop masivamente durante el Heisei (anime, manga, videojuegos). Â¿Es eso soft power? Â¿En quÃ© se diferencia de la exportaciÃ³n cultural que hacen EE. UU. o Europa?'
      ]
    },
    'Reiwa': {
      nivel: 'ESO Â· Bachillerato Â· Universidad',
      preguntas: [
        'El manga Reiwa representa protagonistas que buscan "vivir despacio" (æ—¥å¸¸ç³», nichijÅ-kei). Â¿QuÃ© dice eso de la sociedad japonesa actual? Â¿ResonarÃ­a en el alumnado canario?',
        'Por primera vez en su historia, el manga japonÃ©s tiene mÃ¡s lectoras que lectores. Â¿QuÃ© transforma una industria cultural cuando cambia quiÃ©n la consume?'
      ]
    }
  };

  // â”€â”€ Panel activo (solo uno a la vez) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  let activePanel = null;
  let activeBtn   = null;

  function closeActive() {
    if (!activePanel) return;
    activePanel.classList.remove('open');
    if (activeBtn) activeBtn.classList.remove('active');
    activePanel = null;
    activeBtn   = null;
  }

  // â”€â”€ Inyectar botÃ³n + panel en cada .bar â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function initEraQuestions() {
    document.querySelectorAll('.bar').forEach(bar => {
      const nameEl = bar.querySelector('.era-name');
      if (!nameEl) return;
      const eraName = nameEl.textContent.trim();
      const data    = ERA_QUESTIONS[eraName];
      if (!data) return;

      // BotÃ³n ?
      const btn = document.createElement('button');
      btn.type = 'button';
      btn.className = 'era-q-btn';
      btn.textContent = '?';
      btn.setAttribute('aria-label', `Pregunta detonadora: ${eraName}`);
      btn.setAttribute('title', 'Pregunta detonadora para el aula');

      // Panel â€” appended to body so it escapes overflow:hidden scroll
      const panel = document.createElement('div');
      panel.className = 'era-q-panel';
      panel.setAttribute('role', 'dialog');
      panel.innerHTML = `
        <span class="era-q-label">âœ¦ Pregunta detonadora Â· ${eraName}</span>
        <span class="era-q-nivel">${data.nivel}</span>
        <ul class="era-q-list">
          ${data.preguntas.map(q => `<li>${q}</li>`).join('')}
        </ul>`;
      document.body.appendChild(panel);

      function positionPanel() {
        const r = btn.getBoundingClientRect();
        const pw = 260;
        panel.style.width = pw + 'px';
        panel.style.display = 'block';
        const ph = panel.offsetHeight;
        panel.style.display = '';

        // Try above first, fall back to below
        let top, left;
        if (r.top - ph - 10 > 60) {
          top = r.top - ph - 10;
        } else {
          top = r.bottom + 10;
          // Flip arrow to point up
          panel.classList.add('arrow-down-off');
        }
        left = r.left + r.width / 2 - pw / 2;
        // Keep within viewport
        left = Math.max(8, Math.min(left, window.innerWidth - pw - 8));
        top  = Math.max(8, top);

        panel.style.top  = top + 'px';
        panel.style.left = left + 'px';
      }

      btn.onclick = function(e) {
        e.stopPropagation();
        if (activePanel === panel) { closeActive(); return; }
        closeActive();
        positionPanel();
        panel.classList.add('open');
        btn.classList.add('active');
        activePanel = panel;
        activeBtn   = btn;
      };

      panel.addEventListener('click', e => e.stopPropagation());
      bar.appendChild(btn);
    });

    // Close on click outside
    document.addEventListener('click', closeActive);
    document.addEventListener('keydown', e => { if (e.key === 'Escape') closeActive(); });
    // Reposition on scroll
    document.getElementById('sc')?.addEventListener('scroll', () => { if (activePanel) closeActive(); });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initEraQuestions);
  } else {
    initEraQuestions();
  }

})();

