// PROGRESO DEL ITINERARIO (localStorage)
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
(function() {
  const STORE_KEY = 'manga_itin_progress';

  // â”€â”€ Persistencia â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function loadProgress() {
    return SafeStorage.getJSON(STORE_KEY, {});
  }
  function saveProgress(data) {
    SafeStorage.setJSON(STORE_KEY, data);
  }

  // â”€â”€ Panel id â†’ lista de h3 â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function getCardsInPanel(panelId) {
    const panel = document.getElementById(panelId);
    if (!panel) return [];
    return Array.from(panel.querySelectorAll('.itin-card'));
  }

  // â”€â”€ Barra de progreso â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function renderProgressBar(panelId) {
    const wrap = document.getElementById('itin-prog-' + panelId);
    if (!wrap) return;
    const cards = getCardsInPanel(panelId);
    const total = cards.length;
    if (!total) return;
    const progress = loadProgress();
    const done  = cards.filter(c => progress[cardKey(c)]).length;
    const pct   = Math.round((done / total) * 100);
    const fill  = wrap.querySelector('.itin-progress-fill');
    const label = wrap.querySelector('.itin-progress-label');
    if (fill)  fill.style.width = pct + '%';
    if (label) label.textContent = `${done} / ${total} actividades trabajadas`;
  }

  function cardKey(card) {
    return card.querySelector('h3')?.textContent?.trim() || '';
  }

  // â”€â”€ Toggle tarjeta â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function toggleCard(card) {
    const key = cardKey(card);
    if (!key) return;
    const progress = loadProgress();
    if (progress[key]) {
      delete progress[key];
    } else {
      progress[key] = true;
    }
    saveProgress(progress);
    applyCardState(card, !!progress[key]);
    // Update bar for its parent panel
    const panel = card.closest('.itin-panel');
    if (panel) renderProgressBar(panel.id);
  }

  function applyCardState(card, done) {
    card.classList.toggle('itin-done', done);
    const btn = card.querySelector('.itin-progress-btn');
    if (btn) btn.textContent = done ? 'Trabajado' : 'Marcar como trabajado';
  }

  // â”€â”€ Reset panel â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function resetPanel(panelId) {
    const cards = getCardsInPanel(panelId);
    const progress = loadProgress();
    cards.forEach(c => delete progress[cardKey(c)]);
    saveProgress(progress);
    cards.forEach(c => applyCardState(c, false));
    renderProgressBar(panelId);
  }

  // â”€â”€ InicializaciÃ³n â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  function initProgressBars() {
    const panels = ['itin-inf','itin-p1','itin-p2','itin-p3'];
    const progress = loadProgress();

    panels.forEach(panelId => {
      const panel = document.getElementById(panelId);
      if (!panel) return;

      // Inject progress bar before itin-grid
      const grid = panel.querySelector('.itin-grid');
      if (grid && !document.getElementById('itin-prog-' + panelId)) {
        const bar = document.createElement('div');
        bar.className = 'itin-progress-bar-wrap';
        bar.id = 'itin-prog-' + panelId;
        bar.innerHTML = `
          <div class="itin-progress-track">
            <div class="itin-progress-fill" style="width:0%"></div>
          </div>
          <span class="itin-progress-label">0 / 0 actividades trabajadas</span>
          <button type="button" class="itin-reset-btn" title="Reiniciar progreso de este itinerario"
            onclick="resetItinPanel('${panelId}')">â†º Reiniciar</button>`;
        grid.before(bar);
      }

      // Inject "Marcar como trabajado" button into each itin-card
      getCardsInPanel(panelId).forEach(card => {
        if (!card.querySelector('.itin-progress-btn')) {
          const btn = document.createElement('button');
          btn.type = 'button';
          btn.className = 'itin-progress-btn';
          btn.textContent = 'Marcar como trabajado';
          btn.onclick = () => toggleCard(card);
          card.appendChild(btn);
        }
        // Restore saved state
        applyCardState(card, !!progress[cardKey(card)]);
      });

      renderProgressBar(panelId);
    });
  }

  // Expose reset for inline onclick
  window.resetItinPanel = function(panelId) {
    if (confirm('Â¿Reiniciar el progreso de este itinerario?')) resetPanel(panelId);
  };

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initProgressBars);
  } else {
    initProgressBars();
  }

  // Re-render bar when user switches tab (progress bars in hidden panels)
  document.addEventListener('click', function(e) {
    const tab = e.target.closest('.itin-tab');
    if (!tab) return;
    const panelId = tab.getAttribute('aria-controls');
    if (panelId) setTimeout(() => renderProgressBar(panelId), 50);
  });

})();

