/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   RENDERIZADO DEL CATÃLOGO
   Genera dinÃ¡micamente las 280 tarjetas desde CATALOGO[]
â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */

/* â”€â”€ Colores ODS (definidos antes de renderCatalog) â”€â”€ */
const ODS_COLORES = {
  3:'#4C9F38', 4:'#C5192D', 5:'#FF3A21', 8:'#A21942',
  9:'#FD6925', 10:'#DD1367', 11:'#FD9D24', 13:'#3F7E44',
  15:'#56C02B', 16:'#00689D'
};

function renderCatalog() {
  const grid = document.getElementById('catGrid');
  if (!grid) return;

  // Usar catÃ¡logo efectivo (base + ediciones locales)
  const catalogo = CATALOGO_EFECTIVO.length ? CATALOGO_EFECTIVO
    : (typeof CATALOGO !== 'undefined' ? CATALOGO : []);
  if (!catalogo.length) return;

  const fragment = document.createDocumentFragment();

  catalogo.forEach(t => {
    // â”€â”€ Contenedor principal â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    const card = document.createElement('div');
    card.className = 'cat-card';
    card.dataset.uso   = t.uso;
    card.dataset.nivel = t.nivel;
    card.dataset.tip   = t.tip;
    if (t.sensitive) card.dataset.sensitive = 'true';
    if (t.vitrina)   card.dataset.vitrina   = t.vitrina;
    if (t.ods?.length) card.dataset.ods = t.ods.join(' ');

    // â”€â”€ Barra de color â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    const bar = document.createElement('div');
    bar.className = 'cat-card-bar';
    bar.style.background = t.color;
    card.appendChild(bar);

    // â”€â”€ Cuerpo â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    const body = document.createElement('div');
    body.className = 'cat-card-body';

    // TÃ­tulo y autor (textContent: inmune a XSS)
    const titleEl = document.createElement('span');
    titleEl.className = 'cat-title';
    titleEl.textContent = t.titulo;
    body.appendChild(titleEl);

    const authorEl = document.createElement('span');
    authorEl.className = 'cat-author';
    authorEl.textContent = t.autor;
    body.appendChild(authorEl);

    // Badges de uso
    const badgesDiv = document.createElement('div');
    badgesDiv.className = 'cat-badges';
    t.badges.forEach(b => {
      const s = document.createElement('span');
      s.className = 'cat-badge';
      s.style.background = t.color;
      s.textContent = b;
      badgesDiv.appendChild(s);
    });
    body.appendChild(badgesDiv);

    // Badges de nivel
    const nivelDiv = document.createElement('div');
    nivelDiv.className = 'cat-nivel';
    t.niveles.forEach(n => {
      const s = document.createElement('span');
      s.className = 'niv-badge';
      s.textContent = n;
      nivelDiv.appendChild(s);
    });
    body.appendChild(nivelDiv);

    // PerÃ­odo (opcional)
    if (t.periodo) {
      const p = document.createElement('span');
      p.className = 'periodo-badge';
      p.textContent = t.periodo;
      body.appendChild(p);
    }

    // ODS badges
    if (t.ods?.length) {
      const odsDiv = document.createElement('div');
      odsDiv.className = 'ods-badges';
      t.ods.forEach(n => {
        const s = document.createElement('span');
        s.className = 'ods-badge';
        s.dataset.ods = n;
        s.style.background = ODS_COLORES[n] || '#888';
        s.textContent = n;
        odsDiv.appendChild(s);
      });
      body.appendChild(odsDiv);
    }

    // Badge de contenido sensible
    if (t.sensitive) {
      const sens = document.createElement('span');
      const isOrange = t.sens_label?.includes('18+');
      sens.className = 'sens-badge' + (isOrange ? ' orange' : '');
      sens.title = t.sens_label || 'Contenido sensible';
      sens.textContent = 'âš  ' + (t.sens_label || 'Contenido sensible');
      body.appendChild(sens);
    }

    // Acciones (botones)
    const actions = document.createElement('div');
    actions.className = 'cat-card-actions';
    actions.innerHTML =
      `<button type="button" class="cat-comp-btn"
               data-action="toggleCompCard"
               title="AÃ±adir al comparador">âŠ• Comparar</button>` +
      `<button type="button" class="cat-ficha-btn"
               data-action="openFichaCard"
               title="Ver ficha de aula">Ficha aula</button>` +
      `<button type="button" class="cat-ficha-btn"
               style="background:rgba(42,58,122,.08);border-color:rgba(42,58,122,.3)"
               data-action="openRubricaCard"
               title="Generar rÃºbrica IA">RÃºbrica IA</button>` +
      `<button type="button" class="cat-lectura-btn"
               data-action="openLecturaCard"
               title="Ficha de lectura guiada">Lectura</button>`;
    body.appendChild(actions);

    // Enlace OPAC (opcional)
    if (t.opac) {
      const link = document.createElement('a');
      link.className = 'cat-opac-link';
      link.href = t.opac;
      link.target = '_blank';
      link.rel = 'noopener noreferrer';
      link.setAttribute('aria-label', `Buscar Â«${t.titulo}Â» en el catÃ¡logo de la ULPGC`);
      link.textContent = 'Ver en catÃ¡logo ULPGC â†’';
      body.appendChild(link);
    }

    card.appendChild(body);
    fragment.appendChild(card);
  });

  // Un Ãºnico reflow al insertar todo el fragment
  grid.innerHTML = '';
  grid.appendChild(fragment);

  Logger.debug('Catalog', `${catalogo.length} tarjetas renderizadas (${CatalogoLocal.getStats().adds} locales)`);
}


/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   ValidadorEsquema â€” Validador de integridad del catÃ¡logo
   v1.0 Â· El manga como recurso didÃ¡ctico Â· ULPGC

   Problema resuelto:
     Al aÃ±adir tÃ­tulos mediante el editor o importar CSV/JSON, un campo
     mal escrito (ej. uso:'Ciencia' en lugar de 'ciencia') provoca que
     la tarjeta no aparezca en los filtros, el quiz genere preguntas
     incorrectas o el asistente offline no encuentre el tÃ­tulo.
     Sin validaciÃ³n, el error es silencioso y difÃ­cil de depurar.

   Estrategia:
     Â· Se ejecuta una vez al cargar el DOM (tras _refreshCatalogoEfectivo).
     Â· Se ejecuta de nuevo cada vez que el editor guarda un cambio.
     Â· Los errores crÃ­ticos (tÃ­tulo vacÃ­o, uso invÃ¡lido) se loguean siempre.
     Â· En modo DEBUG, se aÃ±ade un banner temporal con el resumen.
     Â· No bloquea el arranque â€” degrada elegantemente.

   Tipos de validaciÃ³n:
     OBLIGATORIO â€” campo ausente o vacÃ­o
     VALOR       â€” valor fuera del conjunto permitido
     TIPO        â€” tipo de dato incorrecto (ej. ods no es array)
     DUPLICADO   â€” tÃ­tulo repetido en el catÃ¡logo efectivo
â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
const ValidadorEsquema = (() => {

  /** Conjuntos de valores vÃ¡lidos */
  const USOS_VALIDOS   = new Set(['historia','emocional','ciencia','filosofia','genero','visual','lenguas','inclusion']);
  const NIVELES_VALIDOS= new Set(['infantil','primaria','secundaria','bachillerato','universidad']);
  const BADGES_VALIDOS = new Set(['Historia','EducaciÃ³n emocional','Ciencia y tecnologÃ­a','FilosofÃ­a y Ã©tica','GÃ©nero e identidad','AlfabetizaciÃ³n visual','Lengua extranjera','InclusiÃ³n']);
  const ODS_VALIDOS    = new Set([3,4,5,9,10,11,13,15,16]);

  /**
   * Valida una sola entrada del catÃ¡logo.
   * @param {Object} entry  - Entrada a validar
   * @param {number} idx    - Ãndice en el array (para mensajes)
   * @returns {string[]}    - Array de mensajes de error (vacÃ­o si OK)
   */
  function _validateEntry(entry, idx) {
    const errors = [];
    const ref = `[${idx}] Â«${entry.titulo || '(sin tÃ­tulo)'}Â»`;

    // â”€â”€ Campos obligatorios â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    if (!entry.titulo || typeof entry.titulo !== 'string' || !entry.titulo.trim()) {
      errors.push(`${ref} â€” OBLIGATORIO: 'titulo' ausente o vacÃ­o`);
    }
    if (!entry.autor || typeof entry.autor !== 'string') {
      errors.push(`${ref} â€” OBLIGATORIO: 'autor' ausente`);
    }
    if (!entry.tip || typeof entry.tip !== 'string') {
      errors.push(`${ref} â€” OBLIGATORIO: 'tip' ausente`);
    }
    if (!entry.uso || typeof entry.uso !== 'string') {
      errors.push(`${ref} â€” OBLIGATORIO: 'uso' ausente`);
    }

    // â”€â”€ ValidaciÃ³n de valores controlados â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    if (entry.uso) {
      const usoPartes = entry.uso.split(' ');
      for (const u of usoPartes) {
        if (!USOS_VALIDOS.has(u)) {
          errors.push(`${ref} â€” VALOR invÃ¡lido: uso='${u}'. VÃ¡lidos: ${[...USOS_VALIDOS].join(', ')}`);
        }
      }
    }

    if (entry.nivel) {
      const nivelPartes = entry.nivel.split(' ');
      for (const n of nivelPartes) {
        if (!NIVELES_VALIDOS.has(n)) {
          errors.push(`${ref} â€” VALOR invÃ¡lido: nivel='${n}'. VÃ¡lidos: ${[...NIVELES_VALIDOS].join(', ')}`);
        }
      }
    }

    // â”€â”€ ValidaciÃ³n de tipos â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    if (entry.badges !== undefined && !Array.isArray(entry.badges)) {
      errors.push(`${ref} â€” TIPO: 'badges' debe ser un array, encontrado: ${typeof entry.badges}`);
    }
    if (Array.isArray(entry.badges)) {
      for (const b of entry.badges) {
        if (!BADGES_VALIDOS.has(b)) {
          errors.push(`${ref} â€” VALOR invÃ¡lido: badge='${b}'`);
        }
      }
    }

    if (entry.ods !== undefined && !Array.isArray(entry.ods)) {
      errors.push(`${ref} â€” TIPO: 'ods' debe ser un array, encontrado: ${typeof entry.ods}`);
    }
    if (Array.isArray(entry.ods)) {
      for (const o of entry.ods) {
        if (!ODS_VALIDOS.has(Number(o))) {
          errors.push(`${ref} â€” VALOR invÃ¡lido: ods=${o}. VÃ¡lidos: ${[...ODS_VALIDOS].join(', ')}`);
        }
      }
    }

    if (entry.niveles !== undefined && !Array.isArray(entry.niveles)) {
      errors.push(`${ref} â€” TIPO: 'niveles' debe ser un array`);
    }

    return errors;
  }

  /**
   * Valida el catÃ¡logo completo.
   * @param {Array} catalogo  - CATALOGO_EFECTIVO o cualquier array de entradas
   * @returns {{ errors: string[], warnings: string[], ok: number }}
   */
  function validate(catalogo) {
    if (!Array.isArray(catalogo)) {
      return { errors: ['El catÃ¡logo no es un array vÃ¡lido.'], warnings: [], ok: 0 };
    }

    const allErrors  = [];
    const warnings   = [];
    const seen       = new Map();  // titulo â†’ primer Ã­ndice

    catalogo.forEach((entry, idx) => {
      // Detectar duplicados
      if (entry.titulo) {
        const tituloNorm = entry.titulo.trim().toLowerCase();
        if (seen.has(tituloNorm)) {
          warnings.push(`TÃ­tulo duplicado: Â«${entry.titulo}Â» (Ã­ndices ${seen.get(tituloNorm)} y ${idx})`);
        } else {
          seen.set(tituloNorm, idx);
        }
      }

      const entryErrors = _validateEntry(entry, idx);
      allErrors.push(...entryErrors);
    });

    return {
      errors:   allErrors,
      warnings: warnings,
      ok:       catalogo.length - new Set(allErrors.map(e => e.split('Â»')[0])).size,
    };
  }

  /**
   * Valida y registra el resultado.
   * En producciÃ³n: Logger.error/warn para errores crÃ­ticos.
   * En DEBUG: banner temporal en pantalla.
   * @param {Array} catalogo
   */
  function validateAndReport(catalogo) {
    const result = validate(catalogo);
    const totalErrors = result.errors.length + result.warnings.length;

    if (!totalErrors) {
      Logger.debug('Esquema', `âœ“ CatÃ¡logo vÃ¡lido: ${catalogo.length} entradas sin errores`);
      return;
    }

    // Loguear siempre los errores crÃ­ticos
    result.errors.forEach(e => Logger.error('Esquema', e));
    result.warnings.forEach(w => Logger.warn('Esquema', w));

    // En modo DEBUG: banner visual temporal
    if (Logger.isDebug) {
      _showValidationBanner(result);
    }
  }

  /**
   * Muestra un banner de validaciÃ³n en pantalla (solo en modo DEBUG).
   * @param {{ errors: string[], warnings: string[] }} result
   */
  function _showValidationBanner(result) {
    const existing = document.getElementById('__esquema_banner__');
    if (existing) existing.remove();

    const banner = document.createElement('div');
    banner.id = '__esquema_banner__';
    Object.assign(banner.style, {
      position: 'fixed', bottom: '4rem', right: '1rem',
      zIndex: '99997',
      background: result.errors.length ? '#7a0000' : '#7a5000',
      color: '#fff', borderRadius: '6px', padding: '.6rem 1rem',
      fontSize: '.75rem', fontFamily: 'sans-serif',
      maxWidth: '320px', lineHeight: '1.5',
      boxShadow: '0 4px 16px rgba(0,0,0,.4)',
    });
    banner.setAttribute('role', 'alert');

    const icon    = result.errors.length ? 'ðŸš¨' : 'âš ï¸';
    const summary = [
      result.errors.length   ? `${result.errors.length} error${result.errors.length > 1 ? 'es' : ''}` : '',
      result.warnings.length ? `${result.warnings.length} aviso${result.warnings.length > 1 ? 's' : ''}` : '',
    ].filter(Boolean).join(' Â· ');

    banner.innerHTML =
      `<strong>${icon} ValidaciÃ³n catÃ¡logo (DEBUG)</strong><br>${summary}<br>` +
      `<small>Ver consola (F12) para detalles</small>` +
      `<button onclick="this.parentElement.remove()" style="position:absolute;top:.3rem;right:.5rem;` +
      `background:none;border:none;color:#fff;cursor:pointer;font-size:.9rem;">âœ•</button>`;

    document.body ? document.body.appendChild(banner) :
      document.addEventListener('DOMContentLoaded', () => document.body.appendChild(banner));

    // Auto-cerrar tras 8 segundos
    setTimeout(() => banner.remove(), 8000);
  }

  return Object.freeze({ validate, validateAndReport });
})();

/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   NotificadorCatalogo â€” DetecciÃ³n de tÃ­tulos nuevos entre visitas
   v1.0 Â· El manga como recurso didÃ¡ctico Â· ULPGC

   Problema resuelto:
     Cuando el bibliotecario actualiza datos.js (o aÃ±ade tÃ­tulos con
     el editor), los docentes que ya habÃ­an visitado el recurso no
     saben que hay nuevos tÃ­tulos disponibles hasta que exploran el
     catÃ¡logo por casualidad.

   Estrategia (sin servidor, 100% offline):
     1. En cada visita, calcula un fingerprint del catÃ¡logo efectivo:
        total de tÃ­tulos + primera y Ãºltima entrada (ligero, O(1)).
     2. Compara con el fingerprint de la Ãºltima visita (SafeStorage).
     3. Si cambia â†’ recupera la lista completa de tÃ­tulos de la visita
        anterior y calcula la diferencia (tÃ­tulos que aparecieron nuevos).
     4. Muestra un banner no intrusivo con los tÃ­tulos nuevos.
     5. Actualiza el fingerprint y la lista en SafeStorage.

   Clave SafeStorage: 'manga_catalog_snapshot'
   Formato: { fp: string, titles: string[], ts: ISO string }
â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
const NotificadorCatalogo = (() => {
  const SNAP_KEY = 'manga_catalog_snapshot';

  /**
   * Calcula el fingerprint del catÃ¡logo actual.
   * @param {Array} catalogo
   * @returns {string}
   */
  function _fingerprint(catalogo) {
    if (!catalogo?.length) return '0';
    return `${catalogo.length}|${catalogo[0]?.titulo||''}|${catalogo[catalogo.length-1]?.titulo||''}`;
  }

  /**
   * Comprueba si el catÃ¡logo cambiÃ³ desde la Ãºltima visita.
   * Si hay tÃ­tulos nuevos, muestra el banner y actualiza el snapshot.
   * Si es la primera visita, guarda el snapshot silenciosamente.
   * @param {Array} catalogo - CATALOGO_EFECTIVO actual
   */
  function check(catalogo) {
    if (!Array.isArray(catalogo) || !catalogo.length) return;

    const currentFp     = _fingerprint(catalogo);
    const currentTitles = new Set(catalogo.map(t => t.titulo).filter(Boolean));
    const snapshot      = SafeStorage.getJSON(SNAP_KEY, null);

    // Primera visita: guardar snapshot silenciosamente
    if (!snapshot) {
      _saveSnapshot(currentFp, currentTitles);
      Logger.debug('Notificador', `Primera visita registrada: ${catalogo.length} tÃ­tulos`);
      return;
    }

    // Sin cambios: nada que hacer
    if (snapshot.fp === currentFp) {
      Logger.debug('Notificador', 'CatÃ¡logo sin cambios desde la Ãºltima visita');
      return;
    }

    // Calcular nuevos tÃ­tulos (en actual pero no en el snapshot anterior)
    const prevTitles = new Set(snapshot.titles || []);
    const newTitles  = [...currentTitles].filter(t => !prevTitles.has(t));
    const delTitles  = [...prevTitles].filter(t => !currentTitles.has(t));

    // Actualizar snapshot antes de mostrar el banner
    _saveSnapshot(currentFp, currentTitles);

    if (!newTitles.length && !delTitles.length) {
      Logger.debug('Notificador', 'Fingerprint cambiÃ³ pero sin diferencias en tÃ­tulos');
      return;
    }

    Logger.debug('Notificador', `Cambios detectados: +${newTitles.length} nuevos, -${delTitles.length} eliminados`);
    _showBanner(newTitles, delTitles, snapshot.ts);
  }

  /**
   * Guarda el snapshot actual en SafeStorage.
   * @param {string} fp
   * @param {Set<string>} titles
   */
  function _saveSnapshot(fp, titles) {
    SafeStorage.setJSON(SNAP_KEY, {
      fp,
      titles: [...titles],
      ts: new Date().toISOString(),
    });
  }

  /**
   * Muestra el banner de novedades.
   * @param {string[]} newTitles    - TÃ­tulos nuevos
   * @param {string[]} delTitles    - TÃ­tulos eliminados
   * @param {string|null} prevTs    - ISO timestamp de la Ãºltima visita
   */
  function _showBanner(newTitles, delTitles, prevTs) {
    const banner = document.createElement('div');
    banner.id = 'catalogo-novedad-banner';
    banner.setAttribute('role', 'status');
    banner.setAttribute('aria-live', 'polite');

    const prevDate = prevTs
      ? new Date(prevTs).toLocaleDateString('es-ES', { day:'numeric', month:'long' })
      : 'tu Ãºltima visita';

    // Construir contenido
    let content = '';
    if (newTitles.length) {
      const listItems = newTitles.slice(0, 5)
        .map(t => `<span class="cn-title">${escapeHtml(t)}</span>`)
        .join('');
      const more = newTitles.length > 5
        ? `<span class="cn-more"> y ${newTitles.length - 5} mÃ¡s</span>`
        : '';
      content += `<span class="cn-label">âœ¦ ${newTitles.length} tÃ­tulo${newTitles.length > 1 ? 's' : ''} nuevo${newTitles.length > 1 ? 's' : ''} desde ${prevDate}:</span>
        <span class="cn-titles">${listItems}${more}</span>`;
    }
    if (delTitles.length) {
      content += `<span class="cn-del">${delTitles.length} tÃ­tulo${delTitles.length > 1 ? 's' : ''} retirado${delTitles.length > 1 ? 's' : ''} del fondo</span>`;
    }

    banner.innerHTML = `
      <div class="cn-body">
        ${content}
        <button type="button" class="cn-close"
                onclick="document.getElementById('catalogo-novedad-banner').remove()"
                aria-label="Cerrar aviso de novedades">âœ•</button>
      </div>`;

    // Insertar con un pequeÃ±o delay para no competir con el render inicial
    const _inject = () => {
      if (!document.body) return;
      document.body.appendChild(banner);
      // Auto-cierre tras 12 segundos si no se interactuÃ³
      setTimeout(() => {
        const b = document.getElementById('catalogo-novedad-banner');
        if (b) { b.style.opacity = '0'; setTimeout(() => b?.remove(), 400); }
      }, 12000);
    };

    if (document.body) {
      setTimeout(_inject, 1200); // esperar al render del catÃ¡logo
    } else {
      document.addEventListener('DOMContentLoaded', () => setTimeout(_inject, 1200));
    }
  }

  /**
   * Descarta el snapshot actual (Ãºtil para resetear en tests).
   */
  function reset() {
    SafeStorage.removeItem(SNAP_KEY);
  }

  return Object.freeze({ check, reset });
})();

/* â•â• INICIALIZACIÃ“N â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */
document.addEventListener('DOMContentLoaded', function () {
  // 1. Renderizar catÃ¡logo desde datos.js
  // 0. Construir catÃ¡logo efectivo (base + ediciones locales del docente)
  _refreshCatalogoEfectivo();

  // 0b. Validar integridad del catÃ¡logo (errores en Logger, banner en DEBUG)
  ValidadorEsquema.validateAndReport(CATALOGO_EFECTIVO);

  // 0c. Notificar tÃ­tulos nuevos desde la Ãºltima visita
  NotificadorCatalogo.check(CATALOGO_EFECTIVO);

  // 1. Renderizar catÃ¡logo de tÃ­tulos
  renderCatalog();

  // 2. Hookear clics en tarjetas del catÃ¡logo (panel de detalle)
  hookCatCardClicks();

  // 3. Registrar listeners directos para oninput/onkeydown/onchange
  _initDirectListeners();

  // 3. Inicializar navegaciÃ³n por teclado en tabs
  ['.cur-tabs', '.itin-tabs', '.sa-tabs', '.rec-tabs', '.univ-tabs'].forEach(sel => {
    initTabKeyboard(sel);
  });
});

/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   BÃšSQUEDA GLOBAL â€” v6.0
   Busca simultÃ¡neamente en:
     Â· CatÃ¡logo (280 tÃ­tulos)
     Â· LÃ­nea del tiempo (.card)
     Â· Itinerarios (.itin-card)
     Â· Situaciones de Aprendizaje (.sa-card)
   â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */

const GLOBAL_SEARCH_MIN = 2;   // mÃ­nimo de caracteres para buscar
const GLOBAL_SEARCH_MAX = 8;   // mÃ¡ximo de resultados por secciÃ³n

function globalSearch(q) {
  const term  = q.trim().toLowerCase();
  const words = term.length >= GLOBAL_SEARCH_MIN
    ? term.split(/\s+/).filter(Boolean)
    : [];

  // Toggle clear button
  const clearBtn = document.getElementById('globalSearchClear');
  if (clearBtn) clearBtn.classList.toggle('visible', words.length > 0);

  // Also feed the existing catalog search
  const catInput = document.getElementById('catalogSearch');
  if (catInput && catInput.value !== q) catInput.value = q;
  if (typeof searchCatalog === 'function') searchCatalog(q);

  if (words.length === 0) {
    closeGlobalSearch();
    return;
  }

  // â”€â”€ Gather results â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  const results = {
    catalogo:    _searchSection('.cat-card',  _catCardData,    words, GLOBAL_SEARCH_MAX, '#catalogo'),
    timeline:    _searchSection('.tl .card',  _timelineData,   words, GLOBAL_SEARCH_MAX, '#main-content'),
    itinerarios: _searchSection('.itin-card', _itinCardData,   words, GLOBAL_SEARCH_MAX, '#itinerarios'),
    situaciones: _searchSection('.sa-card',   _saCardData,     words, GLOBAL_SEARCH_MAX, '#situaciones'),
  };

  // â”€â”€ Render â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  _renderGlobalResults(results, words, q);
}

// â”€â”€ Data extractors per card type â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _catCardData(card) {
  return {
    title:  card.querySelector('.cat-title')?.textContent  || '',
    sub:    card.querySelector('.cat-author')?.textContent || '',
    tip:    card.dataset.tip || '',
    color:  card.querySelector('.cat-card-bar')?.style.background || '#888',
    tag:    'CatÃ¡logo',
    scroll: function() {
      card.scrollIntoView({ behavior: 'smooth', block: 'center' });
      card.style.outline = '3px solid var(--gold)';
      setTimeout(() => card.style.outline = '', 1800);
    },
  };
}

function _timelineData(card) {
  const col = card.closest('.col');
  const bar = col?.querySelector('.bar');
  // Get bar background-color from style or computed
  const color = bar?.style.background || bar?.style.backgroundColor || '#8a7a60';
  return {
    title:  card.querySelector('.ct')?.textContent  || card.textContent.trim().slice(0, 60),
    sub:    card.querySelector('.ca')?.textContent  || '',
    tip:    card.dataset.tip || '',
    color:  color,
    tag:    'LÃ­nea del tiempo',
    scroll: function() {
      const sc = document.getElementById('sc');
      if (col && sc) {
        const colLeft = col.offsetLeft - sc.offsetWidth / 2 + col.offsetWidth / 2;
        sc.scrollTo({ left: colLeft, behavior: 'smooth' });
      }
      card.style.outline = '3px solid var(--gold)';
      setTimeout(() => card.style.outline = '', 1800);
    },
  };
}

function _itinCardData(card) {
  return {
    title:  card.querySelector('h3')?.textContent || '',
    sub:    card.querySelector('.itin-meta')?.textContent || '',
    tip:    card.querySelector('.itin-titles')?.textContent || '',
    color:  '#2a5a2a',
    tag:    'Itinerarios',
    scroll: function() {
      card.scrollIntoView({ behavior: 'smooth', block: 'center' });
      card.style.outline = '3px solid #2a5a2a';
      setTimeout(() => card.style.outline = '', 1800);
    },
  };
}

function _saCardData(card) {
  return {
    title:  card.querySelector('h3')?.textContent || '',
    sub:    card.querySelector('.sa-meta')?.textContent || '',
    tip:    card.querySelector('.sa-block p')?.textContent?.slice(0, 120) || '',
    color:  '#2a3a7a',
    tag:    'Situaciones de aprendizaje',
    scroll: function() {
      card.scrollIntoView({ behavior: 'smooth', block: 'center' });
      card.style.outline = '3px solid #2a3a7a';
      setTimeout(() => card.style.outline = '', 1800);
    },
  };
}

// â”€â”€ Generic section searcher â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _searchSection(selector, dataFn, words, max, sectionHref) {
  const found = [];
  document.querySelectorAll(selector).forEach(card => {
    if (found.length >= max) return;
    const data = dataFn(card);
    const haystack = (data.title + ' ' + data.sub + ' ' + data.tip).toLowerCase();
    if (words.every(w => haystack.includes(w))) {
      found.push({ ...data, card });
    }
  });
  return { items: found, href: sectionHref };
}

// â”€â”€ Render results panel â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _renderGlobalResults(results, words, rawQuery) {
  const panel = document.getElementById('globalResultsPanel');
  const list  = document.getElementById('globalResultsList');
  const count = document.getElementById('grpCount');
  if (!panel || !list) return;

  const sectionLabels = {
    catalogo:    'ðŸ“š CatÃ¡logo',
    timeline:    'â³ LÃ­nea del tiempo',
    itinerarios: 'ðŸ—º Itinerarios',
    situaciones: 'ðŸ“‹ Situaciones de aprendizaje',
  };

  let totalItems = 0;
  let html = '';

  Object.entries(results).forEach(([key, {items, href}]) => {
    if (items.length === 0) return;
    totalItems += items.length;

    html += `<div class="grp-section">`;
    html += `<div class="grp-section-label">
      ${sectionLabels[key]}
      <span class="grp-badge">${items.length}${items.length === GLOBAL_SEARCH_MAX ? '+' : ''}</span>
    </div>`;

    items.forEach((item, idx) => {
      const titleHL = _hlText(item.title, words);
      const subHL   = _hlText((item.sub + (item.tip ? ' Â· ' + item.tip.slice(0,80) : '')).trim(), words);

      html += `<div class="grp-item" role="option" tabindex="0"
        data-section="${key}" data-idx="${idx}"
        onkeydown="if(event.key==='Enter')grpActivate(this)"
        onclick="grpActivate(this)">
        <span class="grp-item-dot" style="background:${item.color}"></span>
        <div class="grp-item-body">
          <span class="grp-item-title">${titleHL}</span>
          ${subHL ? `<span class="grp-item-sub">${subHL}</span>` : ''}
        </div>
        <span class="grp-item-section-tag">${item.tag}</span>
      </div>`;
    });

    html += `</div>`;
  });

  if (totalItems === 0) {
    html = `<div class="grp-empty">
      <strong>Sin resultados para Â«${rawQuery.replace(/</g,'&lt;')}Â»</strong>
      Prueba con palabras mÃ¡s cortas o en espaÃ±ol
    </div>`;
  }

  list.innerHTML = html;
  if (count) count.textContent = totalItems > 0
    ? `${totalItems} resultado${totalItems !== 1 ? 's' : ''}`
    : '';

  // Store scroll callbacks for click handler
  list._callbacks = {};
  Object.entries(results).forEach(([key, {items}]) => {
    items.forEach((item, idx) => {
      list._callbacks[key + '_' + idx] = item.scroll;
    });
  });

  panel.classList.add('open');
  document.getElementById('globalSearch')?.setAttribute('aria-expanded', 'true');
  document.body.style.overflow = 'hidden';
}

function grpActivate(el) {
  const key  = el.dataset.section;
  const idx  = el.dataset.idx;
  const list = document.getElementById('globalResultsList');
  const cb   = list?._callbacks?.[key + '_' + idx];
  closeGlobalSearch();
  // Navigate to section first
  const results_backup = window._grpResultsBackup || {};
  setTimeout(() => {
    if (typeof cb === 'function') cb();
  }, 350);
}

function closeGlobalSearch() {
  const panel = document.getElementById('globalResultsPanel');
  panel?.classList.remove('open');
  document.getElementById('globalSearch')?.setAttribute('aria-expanded', 'false');
  document.body.style.overflow = '';
}

function clearGlobalSearch() {
  const input = document.getElementById('globalSearch');
  if (input) { input.value = ''; input.focus(); }
  const catInput = document.getElementById('catalogSearch');
  if (catInput) catInput.value = '';
  if (typeof searchCatalog === 'function') searchCatalog('');
  if (typeof clearSearch === 'function') clearSearch();
  closeGlobalSearch();
  const clearBtn = document.getElementById('globalSearchClear');
  if (clearBtn) clearBtn.classList.remove('visible');
}

function globalSearchKey(e) {
  if (e.key === 'Escape') { clearGlobalSearch(); return; }
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    document.querySelector('.grp-item')?.focus();
  }
}

// â”€â”€ Text highlight helper â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _hlText(text, words) {
  if (!text) return '';
  let safe = text.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  words.forEach(w => {
    const rx = new RegExp('(' + w.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + ')', 'gi');
    safe = safe.replace(rx, '<mark>$1</mark>');
  });
  return safe;
}

// â”€â”€ Keyboard shortcut Ctrl+K / Cmd+K â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
document.addEventListener('keydown', function(e) {
  if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
    e.preventDefault();
    const input = document.getElementById('globalSearch');
    if (input) { input.focus(); input.select(); }
  }
  if (e.key === 'Escape') {
    if (document.getElementById('globalResultsPanel')?.classList.contains('open')) {
      closeGlobalSearch();
    }
  }
});

