  // â”€â”€ Fetch cover from Google Books (free, no key) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  _fetchGoogleBooksCover(titleText, authorText);

  // â”€â”€ Populate existing vitrina fields â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
  document.getElementById('vitrineStripe').style.background = color;
  document.getElementById('vitrineEraTag').textContent  = 'ðŸ“š CatÃ¡logo completo';
  document.getElementById('vitrineTitle').textContent   = titleText;
  document.getElementById('vitrineAuthor').textContent  = authorText;
  document.getElementById('vitrineDesc').textContent    = tip;

  const periodoEl = document.getElementById('vitrinePeriodo');
  const periodo   = card.querySelector('.periodo-badge')?.textContent || '';
  if (periodoEl) {
    periodoEl.textContent  = periodo ? 'ðŸ—“ ' + periodo : '';
    periodoEl.style.display = periodo ? 'block' : 'none';
  }

  // Meta badges (uso + nivel)
  const metaEl = document.getElementById('vitrineMeta');
  if (metaEl) metaEl.innerHTML = '';

  // OPAC link
  const opacEl = document.getElementById('vitrineOpacLink');
