/* â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
   MEJORA 5 â€” GENERADOR UNIFICADO IA
   
   Â· Tab "Generar" dentro del asistente panel con 4 tipos de doc
   Â· Historial de sesiÃ³n de documentos generados
   Â· openAsistPanelOnTab(tab) para abrir en modo concreto
   Â· Aviso EU AI Act Art.13 & 50 en cada doc generado
   â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â• */

// Historial de documentos generados en la sesiÃ³n
const _iaDocHistory = [];

// â”€â”€ Open asistente panel on a specific tab â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function openAsistPanelOnTab(tab) {
  const panel = document.getElementById('asistPanel');
  if (!panel) return;
  if (!panel.classList.contains('open')) {
    if (typeof toggleAsistPanel === 'function') toggleAsistPanel();
  }
  // Switch tab
  setTimeout(() => _asistSwitchTab(tab), 80);
}

// â”€â”€ Tab switcher for asistPanel â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _asistSwitchTab(tab) {
  const tabs = ['chat', 'generar', 'historial'];
  tabs.forEach(t => {
    const btn = document.getElementById('asistTab_' + t);
    const pane= document.getElementById('asistPane_' + t);
    if (btn)  btn.classList.toggle('active', t === tab);
    if (pane) pane.style.display = (t === tab) ? 'flex' : 'none';
  });
  if (tab === 'historial') _renderIaHistorial();
}

// â”€â”€ Inject tabs into asistPanel on first open â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _ensureAsistTabs() {
  if (document.getElementById('asistTabBar')) return;

  const panel = document.getElementById('asistPanel');
  if (!panel) return;

  // Tab bar
  const tabBar = document.createElement('div');
  tabBar.id = 'asistTabBar';
  tabBar.className = 'asist-tab-bar';
  tabBar.innerHTML = `
    <button type="button" id="asistTab_chat"
      class="asist-tab active" onclick="_asistSwitchTab('chat')">ðŸ’¬ Chat</button>
    <button type="button" id="asistTab_generar"
      class="asist-tab" onclick="_asistSwitchTab('generar')">âœ¦ Generar</button>
    <button type="button" id="asistTab_historial"
      class="asist-tab" onclick="_asistSwitchTab('historial')">ðŸ• Historial</button>
  `;

  // Wrap existing content in chat pane
  const keyWrap   = document.getElementById('asistKeyWrap');
  const messages  = document.getElementById('asistMessages');
  const inputRow  = panel.querySelector('.asist-input-row');
  const ctxPill   = document.getElementById('asistContextPill');
  const euaiStrip = panel.querySelector('.asist-euai-strip');

  const chatPane = document.createElement('div');
  chatPane.id = 'asistPane_chat';
  chatPane.className = 'asist-pane';
  chatPane.style.cssText = 'display:flex;flex-direction:column;flex:1;overflow:hidden;';

  // Move chat elements into chatPane
  [euaiStrip, ctxPill, messages, keyWrap, inputRow].forEach(el => {
    if (el) chatPane.appendChild(el);
  });

  // Generator pane
  const genPane = document.createElement('div');
  genPane.id = 'asistPane_generar';
  genPane.className = 'asist-pane';
  genPane.style.cssText = 'display:none;flex-direction:column;flex:1;overflow-y:auto;padding:.75rem;gap:.6rem;';
  genPane.innerHTML = _buildGenPane();

  // History pane
  const histPane = document.createElement('div');
  histPane.id = 'asistPane_historial';
  histPane.className = 'asist-pane';
  histPane.style.cssText = 'display:none;flex-direction:column;flex:1;overflow-y:auto;padding:.75rem;';
  histPane.innerHTML = '<div id="asistHistList" class="asist-hist-list"></div>';

  // Insert after header
  const hd = panel.querySelector('.asist-hd');
  hd.after(tabBar);
  tabBar.after(chatPane);
  chatPane.after(genPane);
  genPane.after(histPane);
}

// â”€â”€ Generator pane HTML â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
