// â”€â”€ State â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let _genType    = 'ficha';
let _genContext = null;   // { titulo, autor, tip, uso }

function selectGenType(type) {
  _genType = type;
  document.querySelectorAll('.asist-gen-type-btn').forEach(b => b.classList.remove('active'));
  document.getElementById('genType_' + type)?.classList.add('active');
}

// â”€â”€ Pre-fill from catalog context â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Called from setAsistContext (override extension)
const _origSetAsistContext = window.setAsistContext;
window.setAsistContext = function(titulo, autor, tip, uso) {
  if (typeof _origSetAsistContext === 'function') _origSetAsistContext(titulo, autor, tip, uso);
  _genContext = { titulo, autor, tip, uso };
  // Pre-fill genTitulo
  const inp = document.getElementById('genTitulo');
  if (inp && titulo) inp.value = titulo;
  // Show context pill in genPane
  const ctx = document.getElementById('asistGenContext');
  const lbl = document.getElementById('asistGenCtxTitle');
  if (ctx && lbl) { lbl.textContent = titulo; ctx.style.display = 'flex'; }
};

// â”€â”€ Title autocomplete â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function filterGenSuggestions(q) {
  const box = document.getElementById('genSuggestions');
  if (!box || !q || q.length < 2 || typeof CATALOGO === 'undefined') {
    if (box) box.style.display = 'none';
    return;
  }
  const words = q.toLowerCase().split(/\s+/);
  const matches = CATALOGO.filter(t =>
    words.every(w => t.titulo.toLowerCase().includes(w))
  ).slice(0, 6);

  if (!matches.length) { box.style.display = 'none'; return; }

  box.innerHTML = matches.map(t =>
    `<div class="asist-gen-sugg-item" onclick="pickGenTitle('${t.titulo.replace(/'/g,"\\'")}','${(t.autor||'').replace(/'/g,"\\'")}','${(t.uso||'').replace(/'/g,"\\'")}')">
       <span class="asist-gen-sugg-dot" style="background:${t.color}"></span>
       <span>${t.titulo}</span>
       <span class="asist-gen-sugg-author">${t.autor}</span>
     </div>`
  ).join('');
  box.style.display = 'block';
}

function pickGenTitle(titulo, autor, uso) {
  const inp = document.getElementById('genTitulo');
  if (inp) inp.value = titulo;
  document.getElementById('genSuggestions').style.display = 'none';
  _genContext = { titulo, autor, uso };
}

// â”€â”€ Main generator â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
async function runGenerar() {
  const apiKey = sessionStorage.getItem(MANGA_ASIST_KEY) || '';
  const titulo = document.getElementById('genTitulo')?.value.trim();
  const etapa  = document.getElementById('genEtapa')?.value;
  const comps  = Array.from(document.querySelectorAll('.asist-gen-comps input:checked'))
                      .map(c => c.value).join(' Â· ') || 'CCL';
  const output = document.getElementById('asistGenOutput');
  const content= document.getElementById('asistGenContent');
  const btn    = document.getElementById('asistGenBtn');
  const label  = document.getElementById('asistGenOutputLabel');

  if (!titulo) { alert('Introduce un tÃ­tulo de manga.'); return; }
  if (!apiKey) {
    content.innerHTML = '<p style="color:#a00">Introduce tu clave API en el chat para usar el generador.</p>';
    output.style.display = 'block';
    return;
  }

  const typeLabels = {
    ficha: 'ðŸ“‹ Ficha de aula', sa: 'ðŸŽ¯ SituaciÃ³n de aprendizaje',
    rubrica: 'â­ RÃºbrica',    expres: 'âš¡ Actividad exprÃ©s'
  };

  btn.disabled = true;
  btn.textContent = 'Generandoâ€¦';
  output.style.display = 'none';

  const prompts = {
    ficha: `ActÃºa como experto en pedagogÃ­a LOMLOE. Genera una ficha de aula completa para trabajar el manga Â«${titulo}Â» en ${etapa}. Competencias: ${comps}. Incluye: objetivo, actividades secuenciadas, rol del docente, evaluaciÃ³n. Solo HTML limpio (sin markdown).`,

    sa: `Eres experto en didÃ¡ctica y currÃ­culo canario (LOMLOE). Genera una situaciÃ³n de aprendizaje para Â«${titulo}Â» en ${etapa} con ${comps}. Incluye: situaciÃ³n inicial, reto, actividades, metodologÃ­a, evaluaciÃ³n con indicadores. Cita la normativa canaria. Solo HTML limpio.`,

    rubrica: `ActÃºa como experto en evaluaciÃ³n LOMLOE. Genera una rÃºbrica de evaluaciÃ³n 4Ã—4 para Â«${titulo}Â» en ${etapa}. Competencias: ${comps}. Niveles: Inicial Â· En desarrollo Â· Conseguido Â· Excelente. Incluye contexto pedagÃ³gico. Solo HTML limpio con tabla.`,

    expres: `DiseÃ±a una actividad exprÃ©s de 20 minutos con el manga Â«${titulo}Â» para ${etapa}. Competencias: ${comps}. Estructura: arranque (3 min) Â· desarrollo (14 min) Â· cierre (3 min). Materiales mÃ­nimos. Solo HTML limpio.`
  };

  try {
    let html = await _withRetry(
      () => geminiRequest(apiKey, prompts[_genType]),
      { statusEl: content, maxRetries: 3, baseDelay: 1000, onRetry: runGenerar }
    );
    html = html.replace(/```html?[\r\n]?/g,'').replace(/```[\r\n]?/g,'').trim();

    content.innerHTML = `<div class="gen-doc-content">${html}</div>`;
    if (label) label.textContent = `${typeLabels[_genType]} Â· ${titulo} Â· ${etapa}`;
    output.style.display = 'block';

    // Log to session history
    _iaDocHistory.push({
      time:   new Date().toLocaleTimeString('es-ES', {hour:'2-digit', minute:'2-digit'}),
      type:   _genType,
      label:  typeLabels[_genType],
      titulo, etapa, comps,
      html:   content.innerHTML
    });

    // Also log to main session log
    if (typeof logActivity === 'function')
      logActivity('ai', { title: titulo, type: typeLabels[_genType] });

  } catch(e) {
    content.innerHTML = _errorHtml(e, runGenerar, '.5rem');
    output.style.display = 'block';
  } finally {
    btn.disabled = false;
    btn.textContent = 'âœ¦ Generar con Gemini';
  }
}

function copyGenOutput() {
  const html = document.getElementById('asistGenContent')?.innerHTML || '';
  const text = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  navigator.clipboard?.writeText(text).then(() => {
    const btn = document.querySelector('.asist-gen-output-copy');
    if (btn) { btn.textContent = 'âœ“ Copiado'; setTimeout(() => btn.textContent = 'âŽ˜ Copiar', 1800); }
  });
}

function printGenOutput() {
  const label   = document.getElementById('asistGenOutputLabel')?.textContent || 'Documento IA';
  const content = document.getElementById('asistGenContent')?.innerHTML || '';
  const w = window.open('', '_blank', 'width=800,height=700');
  w.document.write(`<!DOCTYPE html><html lang="es"><head>
    <meta charset="UTF-8">
    <title>${label}</title>
    <style>
      body { font-family: Georgia, serif; max-width: 780px; margin: 2cm auto; color: #1a1008; line-height: 1.65; }
      h3, h4 { font-family: 'Palatino', Georgia, serif; color: #2a1a08; margin-top: 1.2em; }
      table { width: 100%; border-collapse: collapse; margin: 1em 0; font-size: .9em; }
      th { background: #f0ebe0; padding: .4em .7em; border: 1px solid #ccc; font-weight: 700; text-align: left; }
      td { padding: .4em .7em; border: 1px solid #ccc; vertical-align: top; }
      .ia-notice { margin-top: 2em; padding: .5em; border-top: 1px solid #ccc;
        font-size: .75em; color: #666; font-style: italic; }
      @media print { .ia-notice { page-break-inside: avoid; } }
    </style>
  </head><body>
    <h2 style="font-size:1.1em;color:#5a3a1a;border-bottom:2px solid #c8b89a;padding-bottom:.4em">${label}</h2>
    ${content}
    <div class="ia-notice">âš  Contenido generado por IA (Gemini). Revisa y adapta antes de usar en el aula. EU AI Act Art. 13 &amp; 50.</div>
  </body></html>`);
  w.document.close();
  setTimeout(() => w.print(), 400);
}

function closeGenOutput() {
  document.getElementById('asistGenOutput').style.display = 'none';
}

// â”€â”€ Render IA document history â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function _renderIaHistorial() {
  const list = document.getElementById('asistHistList');
  if (!list) return;

  if (_iaDocHistory.length === 0) {
    list.innerHTML = '<p class="asist-hist-empty">AÃºn no has generado ningÃºn documento en esta sesiÃ³n.</p>';
    return;
  }

  list.innerHTML = _iaDocHistory.slice().reverse().map((doc, i) => `
    <div class="asist-hist-item">
      <div class="asist-hist-item-hd">
        <span class="asist-hist-item-type">${doc.label}</span>
        <span class="asist-hist-item-time">${doc.time}</span>
      </div>
      <div class="asist-hist-item-meta">${doc.titulo} Â· ${doc.etapa}</div>
      <details class="asist-hist-details">
        <summary>Ver documento</summary>
        <div class="asist-hist-doc-wrap">${doc.html}</div>
      </details>
      <button type="button" class="asist-hist-copy"
        onclick="copyFromHistory(${_iaDocHistory.length - 1 - i})">âŽ˜ Copiar</button>
    </div>
  `).join('');
}

function copyFromHistory(idx) {
  const doc = _iaDocHistory[idx];
  if (!doc) return;
  const text = doc.html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
  navigator.clipboard?.writeText(text).then(() => {
    const btns = document.querySelectorAll('.asist-hist-copy');
    const btn  = btns[_iaDocHistory.length - 1 - idx];
    if (btn) { btn.textContent = 'âœ“ Copiado'; setTimeout(() => btn.textContent = 'âŽ˜ Copiar', 1800); }
  });
}

// â”€â”€ Hook: inject tabs when panel first opens â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const _origToggleAsistPanel = window.toggleAsistPanel;
window.toggleAsistPanel = function() {
  _origToggleAsistPanel?.();
  // Inject tabs after the panel is open
  const panel = document.getElementById('asistPanel');
  if (panel?.classList.contains('open')) {
    _ensureAsistTabs();
    // Default to chat tab
    if (!document.getElementById('asistTabBar')?.dataset.inited) {
      _asistSwitchTab('chat');
      document.getElementById('asistTabBar').dataset.inited = '1';
    }
  }
};


