/**
 * Normaliza un tÃ­tulo para buscarlo en LECTURA_ALIAS.
 * Elimina diacrÃ­ticos, puntuaciÃ³n y reduce espacios mÃºltiples.
 * @param {string} t
 * @returns {string}
 */
function _normalizeTituloLectura(t) {
  return (t || '').normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9 ]/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

