// â”€â”€ Estado interno â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let _emocionPickerOpen  = false;
let _emocionActiveKey   = null;

/**
 * Inyecta los botones de emociÃ³n en #emocionPicker.
 * Solo se llama una vez desde DOMContentLoaded.
 */
function initEmocionBar() {
  const picker = document.getElementById('emocionPicker');
  const toggle = document.getElementById('emocionToggle');
  if (!picker || !toggle) return;

  toggle.addEventListener('click', toggleEmocionPicker);

  // M13: Selector de nivel antes de los botones de emociÃ³n
  const nivelSelector = document.createElement('div');
  nivelSelector.className = 'emocion-nivel-wrap';
  nivelSelector.setAttribute('role', 'group');
  nivelSelector.setAttribute('aria-label', 'Filtrar por nivel educativo');
  nivelSelector.innerHTML = `
    <span class="emocion-nivel-label">Para quÃ© nivel:</span>
    <button type="button" class="emocion-nivel-btn active" data-nivel="" aria-pressed="true">Todos</button>
    <button type="button" class="emocion-nivel-btn" data-nivel="infantil" aria-pressed="false">Infantil</button>
    <button type="button" class="emocion-nivel-btn" data-nivel="primaria" aria-pressed="false">Primaria</button>
    <button type="button" class="emocion-nivel-btn" data-nivel="secundaria" aria-pressed="false">Secundaria</button>
    <button type="button" class="emocion-nivel-btn" data-nivel="bachillerato" aria-pressed="false">Bachillerato</button>`;
  picker.appendChild(nivelSelector);

  // Nivel filter state
  let _emocionNivelFiltro = '';
  nivelSelector.addEventListener('click', e => {
    const btn = e.target.closest('.emocion-nivel-btn');
    if (!btn) return;
    _emocionNivelFiltro = btn.dataset.nivel;
    nivelSelector.querySelectorAll('.emocion-nivel-btn').forEach(b => {
      const active = b === btn;
      b.classList.toggle('active', active);
      b.setAttribute('aria-pressed', String(active));
    });
    // Re-filter if an emotion is already active
    if (_emocionActiveKey) filterByEmocion(_emocionActiveKey);
  });

  picker.innerHTML += EMOCIONES.map(e => `
    <button type="button"
            class="emocion-btn"
            data-key="${e.key}"
            aria-pressed="false"
            title="${e.frase}"
            style="--emocion-color: ${e.color}">
      <span class="emocion-btn-icon" aria-hidden="true">${e.icon}</span>
      <span class="emocion-btn-label">${e.label}</span>
    </button>`
  ).join('');

  // Event delegation para todos los botones
  picker.addEventListener('click', e => {
    const btn = e.target.closest('.emocion-btn');
    if (btn) filterByEmocion(btn.dataset.key);
  });
}

/**
 * Expande o colapsa el panel de selecciÃ³n de emociones.
 * Actualiza aria-expanded y gestiona la visibilidad con animaciÃ³n CSS.
 */
function toggleEmocionPicker() {
  const picker = document.getElementById('emocionPicker');
  const toggle = document.getElementById('emocionToggle');
  if (!picker || !toggle) return;

  _emocionPickerOpen = !_emocionPickerOpen;
  picker.hidden = !_emocionPickerOpen;
  toggle.setAttribute('aria-expanded', String(_emocionPickerOpen));
  toggle.querySelector('.emocion-toggle-chevron').textContent =
    _emocionPickerOpen ? 'â†‘' : 'â†“';

  // Si se cierra, limpiar resultados y estado activo
  if (!_emocionPickerOpen) {
    _emocionActiveKey = null;
    document.getElementById('emocionResults').innerHTML = '';
    document.querySelectorAll('.emocion-btn').forEach(b => {
      b.classList.remove('active');
      b.setAttribute('aria-pressed', 'false');
    });
  }
}

/**
 * Filtra CATALOGO por la emociÃ³n seleccionada y muestra resultados.
 * Si la misma emociÃ³n estÃ¡ activa, la desactiva (toggle).
 *
 * @param {string} key - Clave de EMOCIONES[].key
 */
function filterByEmocion(key) {
  const emocion = EMOCIONES.find(e => e.key === key);
  if (!emocion) return;

  // Deseleccionar todos primero
  document.querySelectorAll('.emocion-btn').forEach(b => {
    b.classList.remove('active');
    b.setAttribute('aria-pressed', 'false');
  });

  // Toggle: si era el mismo, limpiar y salir
  if (_emocionActiveKey === key) {
    _emocionActiveKey = null;
    document.getElementById('emocionResults').innerHTML = '';
    return;
  }

  _emocionActiveKey = key;
  const btn = document.querySelector(`.emocion-btn[data-key="${key}"]`);
  if (btn) { btn.classList.add('active'); btn.setAttribute('aria-pressed', 'true'); }

  // Verificar catÃ¡logo disponible
  if (typeof CATALOGO === 'undefined' || !CATALOGO.length) {
    document.getElementById('emocionResults').innerHTML =
      '<p class="emocion-empty">CatÃ¡logo no disponible. Recarga la pÃ¡gina.</p>';
    return;
  }

  // Filtrar por usos asociados + nivel (M13)
  const nivelFiltro = typeof _emocionNivelFiltro !== 'undefined' ? _emocionNivelFiltro : '';
  const matches = CATALOGO.filter(t => {
    if (!t.uso) return false;
    const matchUso   = emocion.usos.some(u => t.uso.includes(u));
    const matchNivel = !nivelFiltro || (t.nivel && t.nivel.includes(nivelFiltro));
    return matchUso && matchNivel;
  });

  if (!matches.length) {
    document.getElementById('emocionResults').innerHTML = `
      <p class="emocion-empty">
        Sin resultados exactos para esta emociÃ³n.
        <a href="#catalogo" style="color:var(--gold)">Explora el catÃ¡logo â†’</a>
      </p>`;
    return;
  }

  // Seleccionar 4 tÃ­tulos: priorizar los que tienen descripciÃ³n pedagÃ³gica rica
  const withTip    = matches.filter(t => t.tip && t.tip.length > 30);
  const pool       = withTip.length >= 4 ? withTip : matches;
  const step       = Math.max(1, Math.floor(pool.length / 4));
  const selection  = pool.length <= 4
    ? pool.slice(0, 4)
    : [pool[0], pool[step], pool[step * 2], pool[Math.min(step * 3, pool.length - 1)]];

  _renderEmocionResults(selection, emocion);

  // Scroll suave para mostrar los resultados en mÃ³vil
  setTimeout(() => {
    document.getElementById('emocionResults')
      ?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
  }, 60);
}

/**
 * Renderiza las tarjetas de resultado en #emocionResults.
 * Cada tarjeta incluye: tÃ­tulo, autor, uso, nivel, descripciÃ³n breve
 * y dos acciones: Â«ðŸ“– Lectura guiadaÂ» y Â«Ver en catÃ¡logo â†’Â».
 *
 * @param {Object[]} titles  - Array de entradas de CATALOGO
 * @param {Object}   emocion - Entrada de EMOCIONES
 */
function _renderEmocionResults(titles, emocion) {
  const container = document.getElementById('emocionResults');
  if (!container) return;

  const cardsHtml = titles.map((t, i) => {
    const uso       = (t.uso || '').split(' ')[0];
    const color     = '#' + (USO_COLORS_V[uso] || '5A3A1A');
    const usoLabel  = USO_LABELS_V[uso] || uso;
    const nivel     = (t.nivel || t.niveles?.[0] || '').split(' ')[0];
    const nivelLbl  = NIVEL_LABELS_V[nivel] || nivel;
    const tipShort  = t.tip ? t.tip.slice(0, 100) + (t.tip.length > 100 ? 'â€¦' : '') : '';
    const safeTitle = (t.titulo || '').replace(/"/g, '&quot;');
    const safeAutor = (t.autor  || '').split('Â·')[0].trim().replace(/"/g, '&quot;');
    const safeTip   = (t.tip   || '').slice(0, 200).replace(/"/g, '&quot;');

    return `
      <article class="emocion-card" aria-label="${safeTitle}">
        <div class="emocion-card-strip" style="background:${color}" aria-hidden="true"></div>
        <div class="emocion-card-body">
          <span class="emocion-card-title">${t.titulo || ''}</span>
          <span class="emocion-card-author">${safeAutor}</span>
          <div class="emocion-card-meta">
            <span class="emocion-card-uso" style="background:${color}">${usoLabel}</span>
            ${nivelLbl ? `<span class="emocion-card-nivel">${nivelLbl}</span>` : ''}
          </div>
          ${tipShort ? `<p class="emocion-card-tip">${tipShort}</p>` : ''}
          <div class="emocion-card-actions">
            <button type="button"
                    class="emocion-card-btn emocion-card-lectura"
                    data-idx="${i}"
                    data-titulo="${safeTitle}"
                    data-autor="${safeAutor}"
                    data-nivel="${t.nivel || ''}"
                    data-uso="${t.uso || ''}"
                    data-tip="${safeTip}"
                    aria-label="Abrir ficha de lectura guiada de ${safeTitle}">
              ðŸ“– Lectura guiada
            </button>
            <button type="button"
                    class="emocion-card-btn emocion-card-catalogo"
                    data-uso="${uso}"
                    aria-label="Ver ${safeTitle} en el catÃ¡logo">
              Ver en catÃ¡logo â†’
            </button>
          </div>
        </div>
      </article>`;
  }).join('');

  container.innerHTML = `
    <div class="emocion-results-hd">
      <span class="emocion-results-frase">${emocion.frase}</span>
      <span class="emocion-results-count">${titles.length} tÃ­tulo${titles.length !== 1 ? 's' : ''} del fondo</span>
    </div>
    <div class="emocion-cards-grid">${cardsHtml}</div>
    <div class="emocion-results-ft">
      <button type="button" class="emocion-ver-todos" data-uso="${emocion.usos[0]}">
        Ver todos los tÃ­tulos de esta categorÃ­a en el catÃ¡logo â†’
      </button>
    </div>`;

  // Adjuntar listeners (no inline onclick)
  container.querySelectorAll('.emocion-card-lectura').forEach(btn => {
    btn.addEventListener('click', () => {
      // _makeVirtualCard estÃ¡ definido en app.js (mismo fichero, cargado antes)
      const vCard = _makeVirtualCard(
        btn.dataset.titulo,
        btn.dataset.autor,
        btn.dataset.tip,
        btn.dataset.uso,
        btn.dataset.nivel
      );
      openLectura(vCard);
    });
  });

  container.querySelectorAll('.emocion-card-catalogo, .emocion-ver-todos').forEach(btn => {
    btn.addEventListener('click', () => {
      const uso = btn.dataset.uso;
      filterUso(uso);
      setCatalogMode('biblioteca');
      setTimeout(() => {
        document.getElementById('catalogo')?.scrollIntoView({ behavior: 'smooth' });
      }, 50);
    });
  });
}

