function _quizGetPreguntas(title, nivel, uso) {
  // 1. Buscar por tÃ­tulo exacto
  const banco = QUIZ_BANCO[title];
  if (banco) {
    const qs = banco.niveles?.[nivel] || Object.values(banco.niveles || {})[0];
    if (qs?.length) return qs;
  }

  // 2. Buscar por alias (mismo que lectura guiada)
  const normKey  = _normalizeTituloLectura(title);
  const aliasKey = LECTURA_ALIAS[normKey];
  if (aliasKey && QUIZ_BANCO[aliasKey]) {
    const qs = QUIZ_BANCO[aliasKey].niveles?.[nivel]
            || Object.values(QUIZ_BANCO[aliasKey].niveles || {})[0];
    if (qs?.length) return qs;
  }

  // 3. GeneraciÃ³n automÃ¡tica desde datos del catÃ¡logo
  //    Proporciona 4 preguntas especÃ­ficas para el tÃ­tulo sin banco.
  const autoQs = _quizAutoGenerar(title, nivel, uso);
  if (autoQs?.length) {
    Logger.debug('Quiz', `Auto-generadas ${autoQs.length} preguntas para Â«${title}Â»`);
    return autoQs;
  }

  // 4. Fallback genÃ©rico por uso pedagÃ³gico (Ãºltimo recurso)
  const usoKey = (uso || '').split(' ')[0];
  return QUIZ_FALLBACK[usoKey] || QUIZ_FALLBACK.visual;
}

// â”€â”€ openQuiz / closeQuiz â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/**
 * Abre el modal de quiz para la tarjeta de catÃ¡logo dada.
 * Detecta niveles disponibles y muestra selector si hay mÃ¡s de uno.
 *
 * @param {HTMLElement} card - cat-card o virtual card
 */
window.openQuiz = function(card) {
  if (!card) return;

  const title  = (card.querySelector('.cat-title')?.textContent  || '').trim();
  const autor  = (card.querySelector('.cat-author')?.textContent || '').trim();
  const uso    = (card.getAttribute('data-uso')    || 'visual').split(' ')[0];
  const nivStr = (card.getAttribute('data-nivel')  || 'secundaria');
  const niveles = nivStr.split(/\s+/).filter(Boolean);

  document.getElementById('quizTitleLine').textContent = title;

  // Selector de nivel (pestaÃ±as)
  const tabsEl = document.getElementById('quizNivelTabs');
  tabsEl.innerHTML = '';

  const nivelLabels = { infantil:'Infantil', primaria:'Primaria',
    secundaria:'Secundaria', bachillerato:'Bachillerato', universidad:'Universidad' };

  // Niveles disponibles: los del catÃ¡logo + los que tienen banco especÃ­fico
  const bancoDef    = QUIZ_BANCO[title] || QUIZ_BANCO[LECTURA_ALIAS[_normalizeTituloLectura(title)]];
  const bancoLevels = bancoDef ? Object.keys(bancoDef.niveles || {}) : [];
  const allLevels   = [...new Set([...niveles, ...bancoLevels])].filter(Boolean);
  const showLevels  = allLevels.length > 0 ? allLevels : ['secundaria'];

  showLevels.forEach((n, i) => {
    const btn = document.createElement('button');
    btn.type = 'button';
    btn.className = 'quiz-nivel-tab' + (i === 0 ? ' active' : '');
    btn.textContent = nivelLabels[n] || n;
    btn.setAttribute('role', 'tab');
    btn.setAttribute('aria-selected', i === 0 ? 'true' : 'false');
    btn.addEventListener('click', () => {
      tabsEl.querySelectorAll('.quiz-nivel-tab').forEach(b => {
        b.classList.remove('active');
        b.setAttribute('aria-selected', 'false');
      });
      btn.classList.add('active');
      btn.setAttribute('aria-selected', 'true');
      _quizStart(title, n, uso);
    });
    tabsEl.appendChild(btn);
  });

  _quizStart(title, showLevels[0], uso);

  document.getElementById('quizOverlay').classList.add('open');
  document.body.style.overflow = 'hidden';
  FocusTrap.activate(document.getElementById('quizModal'));
  if (typeof logActivity === 'function') logActivity('viewed', { title, section: 'Quiz' });
};

window.closeQuiz = function() {
  document.getElementById('quizOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
  _quizState = null;
  FocusTrap.deactivate();
};

// â”€â”€ _quizStart â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/**
 * Inicializa el estado de quiz para tÃ­tulo + nivel y renderiza la primera pregunta.
 */
function _quizStart(title, nivel, uso) {
  const preguntas = _quizGetPreguntas(title, nivel, uso);

  _quizState = { title, nivel, preguntas, current: 0, score: 0, answered: 0, answered_reflection: 0 };

  // Mostrar puntuaciÃ³n previa si existe
  const scores  = _quizLoadScores();
  const prevKey = title + '|' + nivel;
  const badge   = document.getElementById('quizScoreBadge');
  if (scores[prevKey]) {
    const s = scores[prevKey];
    badge.textContent = `SesiÃ³n: ${s.correct}/${s.total} correctas`;
    badge.hidden = false;
  } else {
    badge.hidden = true;
  }

  document.getElementById('quizNextBtn').hidden = true;
  _quizRenderQuestion();
}

// â”€â”€ _quizRenderQuestion â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/**
 * Renderiza la pregunta activa en #quizBody.
 * Si se han agotado las preguntas, llama a _quizRenderResult().
 */
function _quizRenderQuestion() {
  const state = _quizState;
  if (!state) return;

  const body = document.getElementById('quizBody');
  const nextBtn = document.getElementById('quizNextBtn');

  if (state.current >= state.preguntas.length) {
    _quizRenderResult();
    return;
  }

  const q     = state.preguntas[state.current];
  const total = state.preguntas.length;
  const num   = state.current + 1;
  const isReflexion = q.respuesta === null;

  const tipoBadge = {
    comprension: { label: 'ComprensiÃ³n',  color: '#2a5a8a' },
    inferencia:  { label: 'Inferencia',   color: '#4a2a6a' },
    curriculo:   { label: 'CurrÃ­culo',    color: '#2a6a4a' },
    reflexion:   { label: 'ðŸ’¬ ReflexiÃ³n',  color: '#7a5a0a' },
  }[q.tipo] || { label: q.tipo, color: '#444' };

  body.innerHTML = `
    <div class="quiz-progress">
      <div class="quiz-progress-bar">
        <div class="quiz-progress-fill" style="width:${((num-1)/total)*100}%"></div>
      </div>
      <span class="quiz-progress-label">${num} / ${total}</span>
    </div>
    <div class="quiz-question-wrap">
      <span class="quiz-tipo-badge" style="background:${tipoBadge.color}">${tipoBadge.label}</span>
      ${isReflexion ? '<span class="quiz-reflexion-note">ðŸ’¬ Pregunta de reflexiÃ³n â€” no hay respuesta Ãºnica</span>' : ''}
      <p class="quiz-question-text">${q.p}</p>
      <div class="quiz-opciones" role="group" aria-label="Opciones de respuesta">
        ${q.opciones.map((op, i) => `
          <button type="button"
                  class="quiz-opcion"
                  data-idx="${i}"
                  aria-label="OpciÃ³n ${i+1}: ${op}">
            <span class="quiz-opcion-letra" aria-hidden="true">${['A','B','C','D'][i]}</span>
            <span class="quiz-opcion-text">${op}</span>
          </button>`).join('')}
      </div>
      <div class="quiz-feedback" id="quizFeedback" aria-live="assertive"></div>
    </div>`;

  nextBtn.hidden = true;
  nextBtn.onclick = () => {
    state.current++;
    _quizRenderQuestion();
  };

  // Event delegation sobre opciones
  body.querySelector('.quiz-opciones').addEventListener('click', e => {
    const btn = e.target.closest('.quiz-opcion');
    if (!btn || btn.disabled) return;
    _quizHandleAnswer(parseInt(btn.dataset.idx, 10));
  });
}

// â”€â”€ _quizHandleAnswer â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/**
 * Procesa la respuesta del alumno: muestra feedback y actualiza puntuaciÃ³n.
 * @param {number} idx - Ãndice de la opciÃ³n seleccionada (0-based)
 */
function _quizHandleAnswer(idx) {
  const state = _quizState;
  if (!state) return;

  const q         = state.preguntas[state.current];
  const isReflexion = q.respuesta === null;
  const isCorrect   = !isReflexion && idx === q.respuesta;

  // Deshabilitar todas las opciones
  const opcBtns = document.querySelectorAll('.quiz-opcion');
  opcBtns.forEach((b, i) => {
    b.disabled = true;
    if (isReflexion) {
      b.classList.add('quiz-opcion-reflexion');
    } else if (i === q.respuesta) {
      b.classList.add('quiz-opcion-correct');
    } else if (i === idx) {
      b.classList.add('quiz-opcion-wrong');
    }
  });

  // Actualizar puntuaciÃ³n
  if (isReflexion) {
    state.answered_reflection++;
  } else {
    state.answered++;
    if (isCorrect) state.score++;
  }

  // Feedback
  const feedback = document.getElementById('quizFeedback');
  if (isReflexion) {
    feedback.innerHTML = `
      <div class="quiz-feedback-reflexion">
        <strong>ðŸ’¬ Pregunta de reflexiÃ³n</strong>
        <p>${q.explicacion}</p>
      </div>`;
  } else if (isCorrect) {
    feedback.innerHTML = `
      <div class="quiz-feedback-correct">
        <strong>âœ“ Correcto</strong>
        <p>${q.explicacion}</p>
      </div>`;
  } else {
    feedback.innerHTML = `
      <div class="quiz-feedback-wrong">
        <strong>âœ— Respuesta correcta: ${['A','B','C','D'][q.respuesta]}</strong>
        <p>${q.explicacion}</p>
      </div>`;
  }

  // Mostrar botÃ³n Siguiente
  const nextBtn = document.getElementById('quizNextBtn');
  const isLast  = state.current >= state.preguntas.length - 1;
  nextBtn.textContent = isLast ? 'Ver resultado â†’' : 'Siguiente â†’';
  nextBtn.hidden = false;
}

// â”€â”€ _quizRenderResult â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€

/**
 * Renderiza la pantalla de resultado final.
 */
function _quizRenderResult() {
  const state   = _quizState;
  const body    = document.getElementById('quizBody');
  const nextBtn = document.getElementById('quizNextBtn');
  nextBtn.hidden = true;

  _quizPersist();

  const pct  = state.answered > 0 ? Math.round((state.score / state.answered) * 100) : 0;
  const msg  = pct >= 80 ? 'Â¡Excelente dominio del contenido! ðŸŒŸ'
             : pct >= 60 ? 'Buen trabajo. Repasa las preguntas falladas.'
             : pct >= 40 ? 'Hay margen de mejora. Â¿Has leÃ­do toda la obra?'
             :             'Te recomendamos releer la obra y probar de nuevo.';

  const reflexText = state.answered_reflection > 0
    ? `<p class="quiz-result-reflection">
        + ${state.answered_reflection} pregunta${state.answered_reflection > 1 ? 's' : ''} de reflexiÃ³n
        respondida${state.answered_reflection > 1 ? 's' : ''} (sin puntuaciÃ³n Ãºnica)
       </p>`
    : '';

  body.innerHTML = `
    <div class="quiz-result">
      <div class="quiz-result-circle">
        <span class="quiz-result-pct">${pct}%</span>
        <span class="quiz-result-fraction">${state.score}/${state.answered}</span>
      </div>
      <p class="quiz-result-msg">${msg}</p>
      ${reflexText}
      <div class="quiz-result-actions">
        <button type="button" class="quiz-btn quiz-btn-retry"
                onclick="_quizStart('${state.title.replace(/'/g,"\\'")}','${state.nivel}','')">
          â†» Repetir quiz
        </button>
        <button type="button" class="quiz-btn quiz-btn-lectura"
                id="quizOpenLecturaBtn">
          ðŸ“– Ir a ficha de lectura
        </button>
      </div>
    </div>`;

  // Hook lectura guiada
  document.getElementById('quizOpenLecturaBtn')?.addEventListener('click', () => {
    closeQuiz();
    // Buscar la tarjeta en el catÃ¡logo y abrir lectura si existe
    const catCard = [...document.querySelectorAll('.cat-card')]
      .find(c => c.querySelector('.cat-title')?.textContent.trim() === state.title);
    if (catCard) {
      openLectura(catCard);
    } else {
      const vCard = _makeVirtualCard(state.title, '', '', '', state.nivel);
      openLectura(vCard);
    }
  });
}

// â”€â”€ InyecciÃ³n del botÃ³n ðŸŽ¯ Quiz en cat-card-actions â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
document.addEventListener('DOMContentLoaded', function() {
  // Inyectar en las tarjetas del catÃ¡logo generadas por renderCatalog()
  // Se usa MutationObserver porque renderCatalog() es diferido.
  function injectQuizButtons(root) {
    (root || document).querySelectorAll('.cat-card').forEach(card => {
      const actions = card.querySelector('.cat-card-actions');
      if (!actions || actions.querySelector('.cat-quiz-btn')) return;
      const btn = document.createElement('button');
      btn.type      = 'button';
      btn.className = 'cat-quiz-btn';
      btn.title     = 'Quiz de comprensiÃ³n offline';
      btn.textContent = 'ðŸŽ¯ Quiz';
      btn.addEventListener('click', () => window.openQuiz(card));
      actions.appendChild(btn);
    });
  }

  // Intento inicial y observer para tarjetas generadas dinÃ¡micamente
  injectQuizButtons();
  const catGrid = document.getElementById('catGrid') || document.getElementById('catalogo');
  if (catGrid && window.MutationObserver) {
    new MutationObserver(() => injectQuizButtons(catGrid))
      .observe(catGrid, { childList: true, subtree: true });
  }

  // Escape key
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' &&
        document.getElementById('quizOverlay')?.classList.contains('open')) {
      window.closeQuiz();
    }
  });

  // Hook en vitrina (botÃ³n Quiz en tarjetas de la lÃ­nea del tiempo)
  const vitrineQuizBtn = document.getElementById('vitrineQuizBtn');
  if (vitrineQuizBtn) {
    vitrineQuizBtn.onclick = () => {
      const vCard = window._currentVitrineCard;
      if (vCard) { closeVitrina?.(); window.openQuiz(vCard); }
    };
  }
});


