// Paleta de colores por tipo de hito
const HITO_COLORES = {
  politico:  '#2a3a7a',
  social:    '#7a5a0a',
  economico: '#1a5a3a',
  cultural:  '#5e3a8a',
  belico:    '#8a2a2a',
};

/**
 * Inicializa el eje canario sincronizado con la lÃ­nea del tiempo.
 * Inyecta las barras de hitos alineadas con las eras japonesas.
 */
function initEjeCanario() {
  const toggle = document.getElementById('ejeCanarioToggle');
  const barsEl = document.getElementById('ejeCanarioBars');
  if (!toggle || !barsEl) return;

  // Toggle expand/collapse
  toggle.addEventListener('click', () => {
    const open = barsEl.hidden;
    barsEl.hidden = !open;
    toggle.setAttribute('aria-expanded', String(open));
    toggle.querySelector('.eje-canario-chevron').textContent = open ? 'â†‘' : 'â†“';
    if (open) _renderEjeCanario(barsEl);
  });
}

/**
 * Renderiza las barras del eje canario.
 * Cada barra corresponde a una era y contiene los hitos de ese perÃ­odo.
 * @param {HTMLElement} container - #ejeCanarioBars
 */
function _renderEjeCanario(container) {
  if (container.dataset.rendered) return;   // Solo una vez
  container.dataset.rendered = '1';

  // Obtener el ancho y orden de las eras desde el DOM para sincronizar
  const eraBars = [...document.querySelectorAll('.bar')];
  const eraNames = [
    'Heian', 'Kamakura Â· Muromachi', 'Sengoku Â· Momoyama',
    'Edo', 'Meiji', 'TaishÅ', 'ShÅwa', 'Heisei', 'Reiwa',
  ];

  container.innerHTML = eraNames.map(era => {
    const data   = HITOS_CANARIOS[era];
    const hitos  = data?.hitos || [];
    const bgGrad = era === 'Reiwa'
      ? 'linear-gradient(135deg,#0e1e10,#162816)'
      : 'linear-gradient(135deg,#0e1020,#1a1030)';

    const hitosHtml = hitos.map(h => `
      <button type="button"
              class="hito-btn"
              style="border-left-color:${HITO_COLORES[h.tipo] || '#5a3a1a'}"
              aria-label="${h.fecha}: ${h.texto}"
              data-detalle="${(h.detalle || '').replace(/"/g,'&quot;')}"
              data-fecha="${h.fecha}"
              data-texto="${h.texto.replace(/"/g,'&quot;')}">
        <span class="hito-fecha">${h.fecha}</span>
        <span class="hito-texto">${h.texto}</span>
      </button>`).join('');

    const noHitosHtml = !hitos.length
      ? '<span class="hito-vacio">Sin registros destacados</span>'
      : '';

    return `
      <div class="eje-era-col">
        <div class="eje-era-name">${era}</div>
        <div class="eje-era-hitos">${hitosHtml}${noHitosHtml}</div>
      </div>`;
  }).join('');

  // Tooltip de detalle para cada hito
  container.addEventListener('click', e => {
    const btn = e.target.closest('.hito-btn');
    if (!btn) return;
    _showHitoDetalle(btn);
  });
}

/**
 * Muestra un panel de detalle del hito seleccionado.
 * @param {HTMLElement} btn - BotÃ³n de hito activado
 */
function _showHitoDetalle(btn) {
  document.querySelectorAll('.hito-detalle-panel').forEach(p => p.remove());
  document.querySelectorAll('.hito-btn.hito-activo').forEach(b => {
    b.classList.remove('hito-activo');
    b.setAttribute('aria-pressed', 'false');
  });

  btn.classList.add('hito-activo');
  btn.setAttribute('aria-pressed', 'true');

  const panel = document.createElement('div');
  panel.className = 'hito-detalle-panel';
  panel.setAttribute('role', 'tooltip');
  panel.innerHTML = `
    <div class="hito-detalle-hd">
      <strong>${btn.dataset.fecha}</strong>
      <button type="button" class="hito-detalle-close" aria-label="Cerrar detalle">âœ•</button>
    </div>
    <p class="hito-detalle-titulo">${btn.dataset.texto}</p>
    <p class="hito-detalle-body">${btn.dataset.detalle}</p>`;
  panel.querySelector('.hito-detalle-close').addEventListener('click', () => {
    panel.remove();
    btn.classList.remove('hito-activo');
    btn.setAttribute('aria-pressed', 'false');
  });
  btn.closest('.eje-era-col')?.appendChild(panel);
}

document.addEventListener('DOMContentLoaded', initEjeCanario);


