// MEJORA 8 â€” PANEL DE REFLEXIÃ“N PARA LA EXPOSICIÃ“N
//
// Permite a los visitantes de la exposiciÃ³n fÃ­sica en la Biblioteca
// del Campus del Obelisco votar su tÃ­tulo favorito y escribir una
// razÃ³n breve. Los votos se almacenan en localStorage del dispositivo
// de la pantalla de exposiciÃ³n. Sin backend, completamente offline.
//
// Arquitectura:
//   EXPO_KEY            â†’ clave de localStorage
//   openExpo/closeExpo  â†’ modal overlay
//   enviarReflexionExpo â†’ guarda el voto y refresca la nube
//   renderExpoCloud     â†’ nube de tÃ­tulos proporcional a los votos
//   resetExpo           â†’ borra todos los datos (solo acceso docente)
// â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•

const EXPO_KEY = 'manga_expo_votos_v1';

/** @returns {{votos:Object, reflexiones:Array}} */
function _expoLoad() {
  return SafeStorage.getJSON(EXPO_KEY, { votos: {}, reflexiones: [] });
}

/** @param {Object} data */
function _expoSave(data) {
  SafeStorage.setJSON(EXPO_KEY, data);
}

/** Abre el modal de la exposiciÃ³n y renderiza la nube actual. */
window.openExpo = function() {
  const _opener = document.activeElement;
  document.getElementById('expoOverlay')?.classList.add('open');
  document.body.style.overflow = 'hidden';
  FocusTrap.activate(document.getElementById('expoModal'), _opener);
  renderExpoCloud();
  _expoUpdateCount();
};

/** Cierra el modal. */
window.closeExpo = function() {
  FocusTrap.deactivate();
  document.getElementById('expoOverlay')?.classList.remove('open');
  document.body.style.overflow = '';
};

/**
 * Guarda el voto del visitante y actualiza la nube.
 */
window.enviarReflexionExpo = function() {
  const tituloEl = document.getElementById('expoTituloInput');
  const razonEl  = document.getElementById('expoRazonInput');
  const titulo   = (tituloEl?.value || '').trim();
  const razon    = (razonEl?.value  || '').trim().slice(0, 200);

  if (!titulo) {
    tituloEl?.focus();
    tituloEl?.classList.add('expo-input-error');
    setTimeout(() => tituloEl?.classList.remove('expo-input-error'), 1500);
    return;
  }

  const data = _expoLoad();
  // Normalizar tÃ­tulo para agrupar variantes
  const key = titulo.toLowerCase().replace(/[^a-z0-9Ã¡Ã©Ã­Ã³ÃºÃ¼Ã± ]/g, '').trim();
  data.votos[key] = (data.votos[key] || 0) + 1;
  data.reflexiones.push({ titulo, razon, ts: Date.now() });
  _expoSave(data);

  // Feedback visual al visitante
  const btn = document.querySelector('.expo-submit-btn');
  if (btn) {
    btn.textContent = 'âœ“ Â¡AÃ±adido!';
    btn.disabled = true;
    setTimeout(() => { btn.textContent = 'âœ¦ AÃ±adir a la pantalla'; btn.disabled = false; }, 2000);
  }
  if (tituloEl) tituloEl.value = '';
  if (razonEl)  razonEl.value  = '';

  renderExpoCloud();
  _expoUpdateCount();
};

/**
 * Renderiza la nube de tÃ­tulos mÃ¡s votados.
 * El tamaÃ±o de cada tÃ­tulo es proporcional a su nÃºmero de votos.
 */
window.renderExpoCloud = function() {
  const cloud = document.getElementById('expoCloud');
  if (!cloud) return;

  const data    = _expoLoad();
  const entries = Object.entries(data.votos)
    .sort(([,a],[,b]) => b - a)
    .slice(0, 28);

  if (!entries.length) {
    cloud.innerHTML = '<span class="expo-cloud-empty">SÃ© el primero en aÃ±adir un tÃ­tulo â†’</span>';
    return;
  }

  const maxVotos = entries[0]?.[1] || 1;
  cloud.innerHTML = entries.map(([key, votos]) => {
    // Recuperar el tÃ­tulo con mayÃºsculas original de la Ãºltima reflexiÃ³n
    const origTitle = (data.reflexiones || [])
      .filter(r => r.titulo.toLowerCase().replace(/[^a-z0-9Ã¡Ã©Ã­Ã³ÃºÃ¼Ã± ]/g,'').trim() === key)
      .at(-1)?.titulo || key;
    const size = (0.9 + (votos / maxVotos) * 1.4).toFixed(2);
    return `<span class="expo-cloud-item"
                  style="font-size:${size}rem"
                  title="${votos} voto${votos !== 1 ? 's' : ''}">${origTitle}</span>`;
  }).join('');
};

/** Actualiza el contador de participaciones. */
function _expoUpdateCount() {
  const countEl = document.getElementById('expoCount');
  if (!countEl) return;
  const data = _expoLoad();
  const total = Object.values(data.votos).reduce((s,v) => s+v, 0);
  countEl.textContent = total
    ? `${total} aportaciÃ³n${total !== 1 ? 'es' : ''} registrada${total !== 1 ? 's' : ''}`
    : 'AÃºn no hay aportaciones';
}

/**
 * Borra todos los datos de la exposiciÃ³n.
 * Pide confirmaciÃ³n antes de borrar.
 */
window.resetExpo = function() {
  if (!confirm('Â¿Borrar todos los votos de la exposiciÃ³n? Esta acciÃ³n no se puede deshacer.')) return;
  SafeStorage.removeItem(EXPO_KEY);
  renderExpoCloud();
  _expoUpdateCount();
};

// Escape key
document.addEventListener('DOMContentLoaded', function() {
  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' &&
        document.getElementById('expoOverlay')?.classList.contains('open')) {
      window.closeExpo();
    }
  });
});


