/**
 * printPasaporte â€” Imprime Ãºnicamente la tarjeta del pasaporte de lectura.
 *
 * Estrategia: igual que printModal() â€” clona #pasaporteCard, lo inyecta
 * en un div fijo que cubre todo el viewport, imprime, y limpia al terminar.
 * Esto evita que el chrome de la aplicaciÃ³n (nav, filtros, FABs) aparezca
 * en la salida impresa, independientemente del @media print global.
 *
 * Compatible con Chrome, Firefox, Safari y el cuadro de diÃ¡logo de impresiÃ³n
 * de iOS (que ignora position:fixed en @media print).
 */
function printPasaporte() {
  const card = document.getElementById('pasaporteCard');
  if (!card) { window.print(); return; }

  // Clonar solo la tarjeta
  const clone = card.cloneNode(true);

  // Contenedor de impresiÃ³n que cubre toda la pantalla
  const wrap = document.createElement('div');
  wrap.id = '__pasaporte_print__';
  wrap.setAttribute('role', 'region');
  wrap.setAttribute('aria-label', 'Pasaporte de lectura â€” versiÃ³n imprimible');
  wrap.appendChild(clone);
  document.body.appendChild(wrap);

  // CSS de impresiÃ³n inyectado dinÃ¡micamente
  const style = document.createElement('style');
  style.id = '__pasaporte_print_style__';
  style.textContent = `
    @media screen {
      #__pasaporte_print__ {
        position: fixed; inset: 0; background: #fff;
        z-index: 999999; display: flex;
        align-items: flex-start; justify-content: center;
        padding: 2rem; box-sizing: border-box; overflow: auto;
      }
      #__pasaporte_print__ .pasaporte-card {
        max-width: 360px; width: 100%; margin: auto;
      }
    }
    @media print {
      body > *:not(#__pasaporte_print__) { display: none !important; }
      #__pasaporte_print__ {
        position: static !important; padding: 0 !important;
        display: block !important; overflow: visible !important;
      }
      #__pasaporte_print__ .pasaporte-card {
        border-color: #8a6020 !important;
        box-shadow: none !important;
        break-inside: avoid;
        max-width: 100% !important;
      }
    }
  `;
  document.head.appendChild(style);

  const origOverflow = document.body.style.overflow;
  document.body.style.overflow = 'hidden';

  function cleanup() {
    if (document.body.contains(wrap))  document.body.removeChild(wrap);
    if (document.head.contains(style)) document.head.removeChild(style);
    document.body.style.overflow = origOverflow;
    window.removeEventListener('afterprint', cleanup);
  }
  window.addEventListener('afterprint', cleanup);

  // Doble rAF: garantiza que el DOM estÃ© pintado antes de invocar print()
  requestAnimationFrame(() => requestAnimationFrame(() => window.print()));
}

// â”€â”€ FAB button hook â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
